fn verify_semantic_scene(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    let mut checks = Vec::new();
    let mut blockers = Vec::new();

    let document_lib = std::fs::read_to_string("crates/boon_document/src/lib.rs")?;
    let document_render_scene =
        std::fs::read_to_string("crates/boon_document/src/render_scene.rs").unwrap_or_default();
    let document_cargo = std::fs::read_to_string("crates/boon_document/Cargo.toml")?;
    let web_host_lib = std::fs::read_to_string("crates/boon_web_host/src/lib.rs")?;
    let web_host_js = std::fs::read_to_string("crates/boon_web_host/static/world_scene_host.js")?;

    for required in [
        "pub struct SemanticScene",
        "pub struct SemanticNode",
        "pub struct SemanticPatch",
        "pub struct SemanticDomSnapshot",
        "pub struct SemanticDomNode",
        "pub struct SemanticWebBridgeSnapshot",
        "pub struct SemanticWebImeEndpoint",
        "pub struct SemanticWebActionRoute",
        "pub enum SemanticWebInputEvent",
        "pub struct SemanticWebSourceDispatch",
        "pub enum SemanticRole",
        "pub enum SemanticPatchOperation",
        "pub fn from_document_layout",
        "pub fn diff",
        "pub fn from_scene",
        "pub fn to_html_fragment",
        "pub fn source_dispatch_for_event",
        "data-boon-id",
        "data-boon-ime-endpoint",
    ] {
        let present = document_lib.contains(required);
        push_audit_check(
            &mut checks,
            &mut blockers,
            format!("semantic-scene:canonical-model:{required}"),
            present,
            format!("crates/boon_document/src/lib.rs contains `{required}`={present}"),
            (!present).then(|| {
                format!("boon_document semantic model is missing required marker `{required}`")
            }),
        );
    }

    for forbidden in [
        "accesskit::",
        "web_sys::",
        "wasm_bindgen::",
        "wgpu::",
        "winit::",
        "glyphon::",
        "boon_native_",
        "app_window",
    ] {
        let present = document_lib.contains(forbidden)
            || document_render_scene.contains(forbidden)
            || document_cargo.contains(forbidden);
        push_audit_check(
            &mut checks,
            &mut blockers,
            format!("semantic-scene:adapter-neutral-forbid:{forbidden}"),
            !present,
            format!("boon_document semantic/render boundary contains `{forbidden}`={present}"),
            present.then(|| {
                format!(
                    "boon_document SemanticScene boundary leaks adapter or GPU marker `{forbidden}`"
                )
            }),
        );
    }
    for required in [
        "pub struct WebSemanticBridgeContract",
        "pub struct WebSemanticBridgeProof",
        "pub fn web_semantic_bridge_contract",
        "pub fn web_semantic_bridge_proof",
        "semantic-ime-action-bridge-contract",
        "semantic-ime-action-bridge-pass",
        "live_bridge_function",
        "supports_live_dom_mount",
        "supports_focus_sync",
        "supports_composition_events",
        "live_bridge_composition_present",
    ] {
        let present = web_host_lib.contains(required);
        push_audit_check(
            &mut checks,
            &mut blockers,
            format!("semantic-scene:web-host-semantic:{required}"),
            present,
            format!("boon_web_host contains `{required}`={present}"),
            (!present).then(|| format!("web host semantic bridge missing `{required}`")),
        );
    }
    for required in [
        "createSemanticWebBridge",
        "browser-semantic-live-bridge-ready",
        "replaceChildren",
        "source_path",
        "source_intent",
        "keydown",
        "setFocus:",
        "focusedSemanticId:",
        "compositionstart",
        "compositionupdate",
        "compositionend",
        "compositionEvents:",
        "beforeinput",
        "insertReplacementText",
        "inputEvents:",
    ] {
        let present = web_host_js.contains(required);
        push_audit_check(
            &mut checks,
            &mut blockers,
            format!("semantic-scene:web-host-live-semantic:{required}"),
            present,
            format!("world_scene_host.js contains `{required}`={present}"),
            (!present).then(|| format!("web host live semantic bridge missing `{required}`")),
        );
    }

    let mut frame = boon_document::DocumentFrame::empty("root");
    let mut button =
        boon_document::DocumentNode::new("save", boon_document::DocumentNodeKind::Button);
    button.parent = Some(boon_document::DocumentNodeId("root".to_owned()));
    button.text = Some(boon_document::TextValue {
        text: "Save".to_owned(),
    });
    button.source_binding = Some(boon_document_model::SourceBinding {
        id: boon_document::SourceBindingId("source:save:press".to_owned()),
        source_path: "toolbar.save".to_owned(),
        intent: "press".to_owned(),
    });

    let mut checkbox =
        boon_document::DocumentNode::new("done", boon_document::DocumentNodeKind::Checkbox);
    checkbox.parent = Some(boon_document::DocumentNodeId("root".to_owned()));
    checkbox
        .style
        .insert("checked".to_owned(), boon_document::StyleValue::Bool(true));
    checkbox.style.insert(
        "accessibility_label".to_owned(),
        boon_document::StyleValue::Text("Done".to_owned()),
    );

    let mut input =
        boon_document::DocumentNode::new("filter", boon_document::DocumentNodeKind::TextInput);
    input.parent = Some(boon_document::DocumentNodeId("root".to_owned()));
    input.text = Some(boon_document::TextValue {
        text: "abc".to_owned(),
    });
    input.source_binding = Some(boon_document_model::SourceBinding {
        id: boon_document::SourceBindingId("source:filter:change".to_owned()),
        source_path: "toolbar.filter".to_owned(),
        intent: "change".to_owned(),
    });
    frame.focus = Some(input.id.clone());
    frame
        .nodes
        .get_mut(&frame.root)
        .ok_or("semantic fixture root missing")?
        .children
        .extend([button.id.clone(), checkbox.id.clone(), input.id.clone()]);
    frame.nodes.insert(button.id.clone(), button);
    frame.nodes.insert(checkbox.id.clone(), checkbox);
    frame.nodes.insert(input.id.clone(), input);

    let mut text = boon_document::SimpleTextMeasurer;
    let layout = boon_document::layout(boon_document::LayoutInput {
        document: &frame,
        viewport: boon_host::Viewport {
            surface: 1,
            width: 320.0,
            height: 180.0,
            scale: 1.0,
        },
        text: &mut text,
        capabilities: boon_document::RenderCapabilities::fake_portable(),
    });
    let scene = boon_document::semantic_scene_from_document_layout(&frame, &layout);
    let button_id = boon_document::SemanticId("semantic:save".to_owned());
    let checkbox_id = boon_document::SemanticId("semantic:done".to_owned());
    let input_id = boon_document::SemanticId("semantic:filter".to_owned());
    let button_semantic = scene.nodes.get(&button_id);
    let checkbox_semantic = scene.nodes.get(&checkbox_id);
    let input_semantic = scene.nodes.get(&input_id);

    push_audit_check(
        &mut checks,
        &mut blockers,
        "semantic-scene:runtime-root-and-node-count",
        scene.root == Some(boon_document::SemanticId("semantic:root".to_owned()))
            && scene.nodes.len() == frame.nodes.len(),
        format!(
            "root={:?}, semantic_nodes={}",
            scene.root,
            scene.nodes.len()
        ),
        (scene.root != Some(boon_document::SemanticId("semantic:root".to_owned()))
            || scene.nodes.len() != frame.nodes.len())
        .then(|| "SemanticScene did not preserve root identity and document node count".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "semantic-scene:runtime-button-action-and-binding",
        button_semantic.is_some_and(|node| {
            node.role == boon_document::SemanticRole::Button
                && node.name.as_deref() == Some("Save")
                && node.actions.press
                && node.actions.focus
                && node.source_binding_id
                    == Some(boon_document::SourceBindingId(
                        "source:save:press".to_owned(),
                    ))
                && node.source_path.as_deref() == Some("toolbar.save")
                && node.bounds.is_some()
        }),
        format!("button_semantic={button_semantic:?}"),
        button_semantic.is_none().then(|| {
            "SemanticScene fixture did not produce a button node with action, binding, and bounds"
                .to_owned()
        }),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "semantic-scene:runtime-checkbox-state-and-value",
        checkbox_semantic.is_some_and(|node| {
            node.role == boon_document::SemanticRole::Checkbox
                && node.name.as_deref() == Some("Done")
                && node.state.checked == Some(true)
                && node.value == Some(boon_document::SemanticValue::Bool { value: true })
        }),
        format!("checkbox_semantic={checkbox_semantic:?}"),
        checkbox_semantic.is_none().then(|| {
            "SemanticScene fixture did not produce checkbox state/value semantics".to_owned()
        }),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "semantic-scene:runtime-focus",
        scene.focused == Some(input_id.clone()),
        format!("focused={:?}", scene.focused),
        (scene.focused != Some(input_id.clone()))
            .then(|| "SemanticScene did not project document focus".to_owned()),
    );

    let mut next = scene.clone();
    next.nodes.remove(&checkbox_id);
    if let Some(mut changed_button) = next.nodes.remove(&button_id) {
        changed_button.name = Some("Save now".to_owned());
        next.nodes.insert(changed_button.id.clone(), changed_button);
    }
    next.focused = Some(button_id.clone());
    let patch = scene.diff(&next);
    let patch_has_remove = patch.operations.iter().any(|operation| {
        matches!(
            operation,
            boon_document::SemanticPatchOperation::RemoveNode { id } if id == &checkbox_id
        )
    });
    let patch_has_upsert = patch.operations.iter().any(|operation| {
        matches!(
            operation,
            boon_document::SemanticPatchOperation::UpsertNode { node }
                if node.id == button_id && node.name.as_deref() == Some("Save now")
        )
    });
    let patch_has_focus = patch.operations.iter().any(|operation| {
        matches!(
            operation,
            boon_document::SemanticPatchOperation::SetFocus { focused: Some(id) }
                if id == &button_id
        )
    });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "semantic-scene:runtime-diff-remove-upsert-focus",
        patch_has_remove && patch_has_upsert && patch_has_focus,
        format!(
            "patch_has_remove={patch_has_remove}, patch_has_upsert={patch_has_upsert}, patch_has_focus={patch_has_focus}"
        ),
        (!(patch_has_remove && patch_has_upsert && patch_has_focus)).then(|| {
            "SemanticScene diff did not emit remove, upsert, and focus operations".to_owned()
        }),
    );
    let dom_snapshot = boon_document::SemanticDomSnapshot::from_scene(&scene);
    let dom_html = dom_snapshot.to_html_fragment();
    let web_bridge = boon_document::SemanticWebBridgeSnapshot::from_scene(&scene);
    let web_html = web_bridge.to_html_fragment();
    let web_text_dispatch =
        web_bridge.source_dispatch_for_event(boon_document::SemanticWebInputEvent::SetText {
            semantic_id: input_id.clone(),
            text: "next".to_owned(),
        });
    let web_press_dispatch =
        web_bridge.source_dispatch_for_event(boon_document::SemanticWebInputEvent::Press {
            semantic_id: button_id.clone(),
        });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "semantic-scene:web-dom-data-boon-id-coverage",
        dom_snapshot.metrics.data_boon_id_count == dom_snapshot.metrics.dom_node_count
            && dom_snapshot.metrics.dom_node_count == scene.nodes.len(),
        format!(
            "dom_node_count={}, data_boon_id_count={}, scene_nodes={}",
            dom_snapshot.metrics.dom_node_count,
            dom_snapshot.metrics.data_boon_id_count,
            scene.nodes.len()
        ),
        (dom_snapshot.metrics.data_boon_id_count != dom_snapshot.metrics.dom_node_count
            || dom_snapshot.metrics.dom_node_count != scene.nodes.len())
        .then(|| {
            "Semantic DOM snapshot must preserve one data-boon-id per semantic node".to_owned()
        }),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "semantic-scene:web-dom-controls-and-ime-endpoint",
        dom_html.contains("data-boon-action-press=\"true\"")
            && dom_html.contains("type=\"checkbox\"")
            && dom_html.contains("aria-checked=\"true\"")
            && dom_html.contains("data-boon-ime-endpoint=\"true\"")
            && dom_snapshot.metrics.text_input_endpoint_count == 1,
        format!(
            "text_input_endpoint_count={}, html={dom_html}",
            dom_snapshot.metrics.text_input_endpoint_count
        ),
        (dom_snapshot.metrics.text_input_endpoint_count != 1).then(|| {
            "Semantic DOM snapshot must expose exactly one text/IME endpoint for the fixture"
                .to_owned()
        }),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "semantic-scene:web-bridge-ime-source-dispatch",
        web_bridge.metrics.ime_endpoint_count == 1
            && web_bridge.metrics.visual_dom_node_count == 0
            && web_text_dispatch.as_ref().is_some_and(|dispatch| {
                dispatch.source_path == "toolbar.filter"
                    && dispatch.source_intent.as_deref() == Some("change")
                    && dispatch.text.as_deref() == Some("next")
            })
            && web_press_dispatch.as_ref().is_some_and(|dispatch| {
                dispatch.source_path == "toolbar.save"
                    && dispatch.source_intent.as_deref() == Some("press")
                    && dispatch.text.is_none()
            })
            && web_html.contains("id=\"boon-semantic-filter\"")
            && !web_html.contains("<canvas")
            && !web_html.contains("<style")
            && !web_html.contains("<svg"),
        format!(
            "web_bridge_metrics={:?}, input_semantic={input_semantic:?}, text_dispatch={web_text_dispatch:?}, press_dispatch={web_press_dispatch:?}",
            web_bridge.metrics
        ),
        (web_bridge.metrics.ime_endpoint_count != 1
            || web_text_dispatch.is_none()
            || web_press_dispatch.is_none())
        .then(|| {
            "Semantic web bridge must expose one IME endpoint and map text/press events to source dispatches".to_owned()
        }),
    );
    let visual_dom_markers_absent =
        !dom_html.contains("<canvas") && !dom_html.contains("<style") && !dom_html.contains("<svg");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "semantic-scene:web-dom-not-visual-renderer",
        visual_dom_markers_absent && dom_snapshot.metrics.visual_dom_node_count == 0,
        format!(
            "visual_dom_node_count={}, visual_markers_absent={visual_dom_markers_absent}",
            dom_snapshot.metrics.visual_dom_node_count
        ),
        (!(visual_dom_markers_absent && dom_snapshot.metrics.visual_dom_node_count == 0)).then(
            || {
                "Semantic DOM snapshot must stay a semantic bridge, not a visual DOM renderer"
                    .to_owned()
            },
        ),
    );

    let web_host_semantic_contract = boon_web_host::web_semantic_bridge_contract();
    let web_host_semantic_proof =
        boon_web_host::web_semantic_bridge_proof(&accessibility_adapter_fixture_scene());
    push_audit_check(
        &mut checks,
        &mut blockers,
        "semantic-scene:web-host-ime-action-bridge-proof",
        web_host_semantic_contract.supports_ime_endpoint
            && web_host_semantic_contract.supports_action_routes
            && web_host_semantic_contract.supports_source_dispatch
            && !web_host_semantic_contract.mirrors_visual_dom
            && web_host_semantic_proof.status == "semantic-ime-action-bridge-pass"
            && web_host_semantic_proof.supports_press_dispatch
            && web_host_semantic_proof.supports_set_text_dispatch
            && web_host_semantic_proof.supports_increment_dispatch
            && web_host_semantic_proof.supports_decrement_dispatch
            && web_host_semantic_proof.visual_dom_node_count == 0
            && web_host_semantic_proof.live_bridge_focus_sync_present
            && web_host_semantic_proof.live_bridge_composition_present
            && !web_host_semantic_proof.html_contains_visual_renderer_marker,
        format!(
            "web_host_semantic_contract={web_host_semantic_contract:?}, web_host_semantic_proof={web_host_semantic_proof:?}"
        ),
        (web_host_semantic_proof.status != "semantic-ime-action-bridge-pass").then(|| {
            "boon_web_host semantic bridge must prove IME/action source dispatch without visual DOM mirroring".to_owned()
        }),
    );

    let report = report_arg(args)
        .unwrap_or_else(|| PathBuf::from("target/reports/unified/semantic-scene.json"));
    write_static_gate_report(
        args,
        "verify-semantic-scene",
        report,
        checks,
        blockers,
        json!({
            "semantic_scene_node_count": scene.nodes.len(),
            "semantic_patch_operation_count": patch.operations.len(),
            "semantic_dom_node_count": dom_snapshot.metrics.dom_node_count,
            "semantic_dom_interactive_node_count": dom_snapshot.metrics.interactive_node_count,
            "semantic_dom_text_input_endpoint_count": dom_snapshot.metrics.text_input_endpoint_count,
            "semantic_dom_visual_node_count": dom_snapshot.metrics.visual_dom_node_count,
            "semantic_dom_html_sha256": boon_runtime::sha256_bytes(dom_html.as_bytes()),
            "semantic_web_ime_endpoint_count": web_bridge.metrics.ime_endpoint_count,
            "semantic_web_action_route_count": web_bridge.metrics.action_route_count,
            "semantic_web_source_routed_action_count": web_bridge.metrics.source_routed_action_count,
            "semantic_web_html_sha256": boon_runtime::sha256_bytes(web_html.as_bytes()),
            "web_host_semantic_bridge_status": web_host_semantic_proof.status,
            "web_host_semantic_bridge_source_dispatch_count": web_host_semantic_proof.source_dispatch_count,
            "web_host_semantic_bridge_source_routed_action_count": web_host_semantic_proof.source_routed_action_count,
            "web_host_semantic_bridge_supports_increment_dispatch": web_host_semantic_proof.supports_increment_dispatch,
            "web_host_semantic_bridge_supports_decrement_dispatch": web_host_semantic_proof.supports_decrement_dispatch,
            "web_host_semantic_bridge_supports_replace_selected_text_dispatch": web_host_semantic_proof.supports_replace_selected_text_dispatch,
            "web_host_semantic_bridge_visual_dom_node_count": web_host_semantic_proof.visual_dom_node_count,
            "web_host_semantic_bridge_live_function_present": web_host_semantic_proof.live_bridge_function_present,
            "web_host_semantic_bridge_live_mount_present": web_host_semantic_proof.live_bridge_mount_present,
            "web_host_semantic_bridge_live_dispatch_present": web_host_semantic_proof.live_bridge_dispatch_present,
            "web_host_semantic_bridge_live_focus_sync_present": web_host_semantic_proof.live_bridge_focus_sync_present,
            "web_host_semantic_bridge_live_composition_present": web_host_semantic_proof.live_bridge_composition_present,
            "adapter_status": "canonical-scene-plus-web-semantic-ime-bridge-snapshot",
            "native_accessibility_adapter_status": "covered-by-verify-accessibility-adapters",
            "web_semantic_adapter_status": "minimal-live-dom-and-ime-route-bridge-implemented"
        }),
    )
}

fn verify_accessibility_adapters(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    let mut checks = Vec::new();
    let mut blockers = Vec::new();

    let document_lib = std::fs::read_to_string("crates/boon_document/src/lib.rs")?;
    let web_host_lib = std::fs::read_to_string("crates/boon_web_host/src/lib.rs")?;
    let web_host_js = std::fs::read_to_string("crates/boon_web_host/static/world_scene_host.js")?;
    let native_window_lib = std::fs::read_to_string("crates/boon_native_app_window/src/lib.rs")?;
    let native_window_cargo = std::fs::read_to_string("crates/boon_native_app_window/Cargo.toml")?;
    let app_window_surface = std::fs::read_to_string("vendor/app_window/src/surface.rs")?;
    let app_window_linux_mod = std::fs::read_to_string("vendor/app_window/src/sys/linux/mod.rs")?;
    let app_window_linux_window =
        std::fs::read_to_string("vendor/app_window/src/sys/linux/window.rs")?;
    let app_window_linux_ax = std::fs::read_to_string("vendor/app_window/src/sys/linux/ax.rs")?;
    let native_playground = std::fs::read_to_string("crates/boon_native_playground/src/main.rs")?;

    for required in [
        "pub struct SemanticDomSnapshot",
        "pub struct SemanticWebBridgeSnapshot",
        "pub struct SemanticWebImeEndpoint",
        "pub struct SemanticWebActionRoute",
        "pub enum SemanticWebInputEvent",
        "pub struct SemanticWebSourceDispatch",
        "pub fn from_scene",
        "pub fn source_dispatch_for_event",
        "data-boon-id",
        "data-boon-ime-endpoint",
    ] {
        let present = document_lib.contains(required);
        push_audit_check(
            &mut checks,
            &mut blockers,
            format!("accessibility-adapters:web-semantic:{required}"),
            present,
            format!("boon_document contains `{required}`={present}"),
            (!present).then(|| format!("web semantic snapshot missing `{required}`")),
        );
    }
    for required in [
        "pub struct WebSemanticBridgeContract",
        "pub struct WebSemanticBridgeProof",
        "pub fn web_semantic_bridge_contract",
        "pub fn web_semantic_bridge_proof",
        "semantic-ime-action-bridge-contract",
        "semantic-ime-action-bridge-pass",
        "live_bridge_function",
        "supports_live_dom_mount",
        "supports_composition_events",
        "live_bridge_composition_present",
    ] {
        let present = web_host_lib.contains(required);
        push_audit_check(
            &mut checks,
            &mut blockers,
            format!("accessibility-adapters:web-host-semantic:{required}"),
            present,
            format!("boon_web_host contains `{required}`={present}"),
            (!present).then(|| format!("web host semantic bridge missing `{required}`")),
        );
    }
    for required in [
        "createSemanticWebBridge",
        "browser-semantic-live-bridge-ready",
        "replaceChildren",
        "source_path",
        "source_intent",
        "keydown",
        "compositionstart",
        "compositionupdate",
        "compositionend",
        "compositionEvents:",
        "beforeinput",
        "insertReplacementText",
        "inputEvents:",
    ] {
        let present = web_host_js.contains(required);
        push_audit_check(
            &mut checks,
            &mut blockers,
            format!("accessibility-adapters:web-host-live-semantic:{required}"),
            present,
            format!("world_scene_host.js contains `{required}`={present}"),
            (!present).then(|| format!("web host live semantic bridge missing `{required}`")),
        );
    }
    for required in [
        "accesskit_tree_update_from_semantic_scene",
        "NativeAccessibilitySnapshot",
        "NativeAccessibilityMetrics",
        "NativeAccessibilityActionRequest",
        "NativeAccessibilityAction",
        "native_accessibility_action_requests_from_accesskit",
        "native_accessibility_world_editor_session_reports_from_requests",
        "NativeWorldEditorSessionActionReport",
        "accesskit::TreeUpdate",
        "pub accessibility_update: Option<accesskit::TreeUpdate>",
        "pub accessibility_actions: Vec<NativeAccessibilityActionRequest>",
        "app_surface.update_accessibility_if_active",
        "app_surface.take_accessibility_action_requests",
        "accesskit.workspace = true",
        "boon_document.workspace = true",
        "boon_scene_model.workspace = true",
        "boon_solid_model.workspace = true",
    ] {
        let present =
            native_window_lib.contains(required) || native_window_cargo.contains(required);
        push_audit_check(
            &mut checks,
            &mut blockers,
            format!("accessibility-adapters:native-accesskit:{required}"),
            present,
            format!("native accessibility boundary contains `{required}`={present}"),
            (!present).then(|| format!("native AccessKit adapter missing `{required}`")),
        );
    }
    for required in [
        "pub fn update_accessibility_if_active",
        "pub fn take_accessibility_action_requests",
        "latest_accessibility_tree_update",
        "accessibility_action_requests",
        "std::mem::take(&mut window_internal.accessibility_action_requests)",
        "adapter.update_if_active",
        "request_initial_tree",
        "deactivate_accessibility",
    ] {
        let present = app_window_surface.contains(required)
            || app_window_linux_mod.contains(required)
            || app_window_linux_window.contains(required)
            || app_window_linux_ax.contains(required);
        push_audit_check(
            &mut checks,
            &mut blockers,
            format!("accessibility-adapters:app-window-live-bridge:{required}"),
            present,
            format!("app_window live accessibility bridge contains `{required}`={present}"),
            (!present)
                .then(|| format!("app_window live accessibility bridge missing `{required}`")),
        );
    }
    let app_window_action_handler_non_panicking =
        !app_window_linux_ax.contains("unimplemented!") && !app_window_linux_ax.contains("todo!()");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "accessibility-adapters:app-window-action-handler-non-panicking",
        app_window_action_handler_non_panicking,
        format!("app_window_action_handler_non_panicking={app_window_action_handler_non_panicking}"),
        (!app_window_action_handler_non_panicking).then(|| {
            "app_window AccessKit action handler must capture unsupported/content actions instead of panicking".to_owned()
        }),
    );
    for required in [
        "preview_semantic_scene_for_shared",
        "preview_native_accessibility_snapshot_for_shared",
        "PreviewWorldEditorSessionState",
        "preview_world_editor_session_for_live_runtime",
        "preview_world_editor_document_layout_snapshot",
        "preview_install_world_editor_layout_snapshot",
        "preview_semantic_scene_for_world_editor_session",
        "preview_native_accessibility_snapshot_for_host",
        "world_editor_session_visual_panel_status",
        "semantic_scene_from_document_layout",
        "cached_document_render_snapshot",
        "layout_frame_override",
        "accessibility_update",
        "context.accessibility_actions",
        "preview_apply_accessibility_actions_with_units",
        "world_editor_session_applied",
        "native_accessibility_world_editor_session_reports_from_requests",
        "preview_focus_node_from_accessibility",
        "preview_set_text_from_accessibility",
        "live_source_event_for_node_action",
        "preview_try_apply_world_editor_input",
        "preview_world_editor_export_artifact_for_report",
        "last_export_artifact",
        "selected-printable-instance-from-export-action",
        "preview_host_world_editor_visible_clicks_update_session",
    ] {
        let present = native_playground.contains(required);
        push_audit_check(
            &mut checks,
            &mut blockers,
            format!("accessibility-adapters:preview-live-tree:{required}"),
            present,
            format!("native playground preview live tree path contains `{required}`={present}"),
            (!present)
                .then(|| format!("native preview live accessibility path missing `{required}`")),
        );
    }
    let document_forbids_platform_adapters = !document_lib.contains("accesskit::")
        && !document_lib.contains("web_sys::")
        && !document_lib.contains("wasm_bindgen::")
        && !document_lib.contains("wgpu::")
        && !document_lib.contains("app_window");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "accessibility-adapters:document-remains-platform-neutral",
        document_forbids_platform_adapters,
        format!("document_forbids_platform_adapters={document_forbids_platform_adapters}"),
        (!document_forbids_platform_adapters).then(|| {
            "boon_document must not import AccessKit, browser, WGPU, or app_window adapter types"
                .to_owned()
        }),
    );

    let scene = accessibility_adapter_fixture_scene();
    let dom_snapshot = boon_document::SemanticDomSnapshot::from_scene(&scene);
    let dom_html = dom_snapshot.to_html_fragment();
    let web_bridge = boon_document::SemanticWebBridgeSnapshot::from_scene(&scene);
    let web_html = web_bridge.to_html_fragment();
    let web_text_dispatch =
        web_bridge.source_dispatch_for_event(boon_document::SemanticWebInputEvent::SetText {
            semantic_id: boon_document::SemanticId("semantic:filter".to_owned()),
            text: "next".to_owned(),
        });
    let web_press_dispatch =
        web_bridge.source_dispatch_for_event(boon_document::SemanticWebInputEvent::Press {
            semantic_id: boon_document::SemanticId("semantic:save".to_owned()),
        });
    let web_increment_dispatch =
        web_bridge.source_dispatch_for_event(boon_document::SemanticWebInputEvent::Increment {
            semantic_id: boon_document::SemanticId("semantic:zoom-in".to_owned()),
        });
    let web_decrement_dispatch =
        web_bridge.source_dispatch_for_event(boon_document::SemanticWebInputEvent::Decrement {
            semantic_id: boon_document::SemanticId("semantic:zoom-out".to_owned()),
        });
    let web_host_semantic_contract = boon_web_host::web_semantic_bridge_contract();
    let web_host_semantic_proof = boon_web_host::web_semantic_bridge_proof(&scene);
    let native_snapshot = boon_native_app_window::accesskit_tree_update_from_semantic_scene(
        &scene,
        "boon-native",
        "verify-accessibility-adapters",
    );

    push_audit_check(
        &mut checks,
        &mut blockers,
        "accessibility-adapters:web-static-dom-contract",
        dom_snapshot.metrics.dom_node_count == scene.nodes.len()
            && dom_snapshot.metrics.data_boon_id_count == dom_snapshot.metrics.dom_node_count
            && dom_snapshot.metrics.text_input_endpoint_count == 1
            && dom_snapshot.metrics.visual_dom_node_count == 0
            && dom_html.contains("data-boon-action-press=\"true\"")
            && dom_html.contains("data-boon-ime-endpoint=\"true\"")
            && !dom_html.contains("<canvas")
            && !dom_html.contains("<style")
            && !dom_html.contains("<svg"),
        format!(
            "dom_node_count={}, data_boon_id_count={}, text_input_endpoint_count={}, visual_dom_node_count={}",
            dom_snapshot.metrics.dom_node_count,
            dom_snapshot.metrics.data_boon_id_count,
            dom_snapshot.metrics.text_input_endpoint_count,
            dom_snapshot.metrics.visual_dom_node_count
        ),
        (dom_snapshot.metrics.dom_node_count != scene.nodes.len()
            || dom_snapshot.metrics.data_boon_id_count != dom_snapshot.metrics.dom_node_count
            || dom_snapshot.metrics.text_input_endpoint_count != 1
            || dom_snapshot.metrics.visual_dom_node_count != 0)
            .then(|| "web semantic snapshot contract failed".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "accessibility-adapters:web-semantic-ime-bridge-contract",
        web_bridge.metrics.dom_node_count == scene.nodes.len()
            && web_bridge.metrics.ime_endpoint_count == 1
            && web_bridge.metrics.source_routed_action_count >= 4
            && web_bridge.metrics.visual_dom_node_count == 0
            && web_text_dispatch.as_ref().is_some_and(|dispatch| {
                dispatch.source_path == "toolbar.filter"
                    && dispatch.source_intent.as_deref() == Some("change")
                    && dispatch.text.as_deref() == Some("next")
            })
            && web_press_dispatch.as_ref().is_some_and(|dispatch| {
                dispatch.source_path == "toolbar.save"
                    && dispatch.source_intent.as_deref() == Some("press")
            })
            && web_increment_dispatch.as_ref().is_some_and(|dispatch| {
                dispatch.source_path == "viewport.zoom"
                    && dispatch.source_intent.as_deref() == Some("increment")
            })
            && web_decrement_dispatch.as_ref().is_some_and(|dispatch| {
                dispatch.source_path == "viewport.zoom"
                    && dispatch.source_intent.as_deref() == Some("decrement")
            })
            && web_html.contains("id=\"boon-semantic-filter\"")
            && web_html.contains("data-boon-action-increment=\"true\"")
            && web_html.contains("data-boon-action-decrement=\"true\"")
            && !web_html.contains("<canvas")
            && !web_html.contains("<style")
            && !web_html.contains("<svg"),
        format!(
            "web_bridge_metrics={:?}, text_dispatch={web_text_dispatch:?}, press_dispatch={web_press_dispatch:?}, increment_dispatch={web_increment_dispatch:?}, decrement_dispatch={web_decrement_dispatch:?}",
            web_bridge.metrics
        ),
        (web_bridge.metrics.ime_endpoint_count != 1
            || web_bridge.metrics.source_routed_action_count < 4
            || web_text_dispatch.is_none()
            || web_press_dispatch.is_none()
            || web_increment_dispatch.is_none()
            || web_decrement_dispatch.is_none())
        .then(|| "web semantic/IME bridge contract failed".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "accessibility-adapters:web-host-semantic-bridge-proof",
        web_host_semantic_contract.supports_ime_endpoint
            && web_host_semantic_contract.supports_action_routes
            && web_host_semantic_contract.supports_source_dispatch
            && !web_host_semantic_contract.mirrors_visual_dom
            && web_host_semantic_proof.status == "semantic-ime-action-bridge-pass"
            && web_host_semantic_proof.ime_endpoint_count == 1
            && web_host_semantic_proof.source_dispatch_count
                == web_host_semantic_proof.source_routed_action_count
            && web_host_semantic_proof.supports_press_dispatch
            && web_host_semantic_proof.supports_set_text_dispatch
            && web_host_semantic_proof.supports_increment_dispatch
            && web_host_semantic_proof.supports_decrement_dispatch
            && web_host_semantic_proof.visual_dom_node_count == 0
            && web_host_semantic_proof.live_bridge_focus_sync_present
            && web_host_semantic_proof.live_bridge_composition_present
            && !web_host_semantic_proof.html_contains_visual_renderer_marker,
        format!(
            "web_host_semantic_contract={web_host_semantic_contract:?}, web_host_semantic_proof={web_host_semantic_proof:?}"
        ),
        (web_host_semantic_proof.status != "semantic-ime-action-bridge-pass").then(|| {
            "boon_web_host semantic bridge must prove IME/action source dispatch without visual DOM mirroring".to_owned()
        }),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "accessibility-adapters:native-accesskit-tree-contract",
        native_snapshot.metrics.semantic_node_count == scene.nodes.len()
            && native_snapshot.metrics.accesskit_node_count == scene.nodes.len()
            && native_snapshot.metrics.node_id_collision_count == 0
            && native_snapshot.metrics.root_present
            && native_snapshot.metrics.focus_present
            && native_snapshot.tree_update.tree.is_some()
            && native_snapshot.tree_update.nodes.iter().any(|(_, node)| {
                node.role() == accesskit::Role::Button
                    && node.supports_action(accesskit::Action::Click)
                    && node.supports_action(accesskit::Action::Focus)
            })
            && native_snapshot.tree_update.nodes.iter().any(|(_, node)| {
                node.role() == accesskit::Role::TextInput
                    && node.supports_action(accesskit::Action::SetValue)
                    && node.supports_action(accesskit::Action::ReplaceSelectedText)
            })
            && native_snapshot.tree_update.nodes.iter().any(|(_, node)| {
                node.role() == accesskit::Role::CheckBox
                    && node.toggled() == Some(accesskit::Toggled::True)
            }),
        format!("native_accessibility_metrics={:?}", native_snapshot.metrics),
        (native_snapshot.metrics.accesskit_node_count != scene.nodes.len()
            || native_snapshot.metrics.node_id_collision_count != 0)
            .then(|| "native AccessKit tree contract failed".to_owned()),
    );
    let repeat = boon_native_app_window::accesskit_tree_update_from_semantic_scene(
        &scene,
        "boon-native",
        "verify-accessibility-adapters",
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "accessibility-adapters:native-accesskit-stable-id-repeat",
        native_snapshot.semantic_node_ids == repeat.semantic_node_ids,
        format!(
            "semantic_node_ids={:?}, repeat={:?}",
            native_snapshot.semantic_node_ids, repeat.semantic_node_ids
        ),
        (native_snapshot.semantic_node_ids != repeat.semantic_node_ids).then(|| {
            "native AccessKit node IDs must be stable across repeated lowering".to_owned()
        }),
    );
    #[derive(Debug)]
    struct NativeWorldEditorSessionProof {
        selected_instance_count: usize,
        export_status: String,
        selected_printable: bool,
        three_mf_status: String,
        three_mf_validation_status: String,
        three_mf_opc_zip_byte_count: usize,
        three_mf_entry_count: usize,
        three_mf_component_count: usize,
        three_mf_slice_count: usize,
        print_printable_instance_count: usize,
        visual_mesh_used_for_manufacturing: bool,
    }

    let native_world_editor_session_result: Result<NativeWorldEditorSessionProof, String> =
        (|| {
            let bundle = boon_solid_model::SolidModelBundle::parametric_car_fixture();
            let visual =
                boon_scene_model::WorldScene::visual_proxy_with_chunks_from_solid_model(&bundle)?;
            let mut session = boon_scene_model::WorldEditorSession::new(visual.scene);
            let scene_for_session = |session: &boon_scene_model::WorldEditorSession| {
                session
                    .semantic_editor_tree(&bundle, "Car editor")
                    .map(|tree| boon_document::SemanticScene::from_world_editor_tree(&tree))
            };
            let node_id_for_name = |scene: &boon_document::SemanticScene,
                                    name: &str|
             -> Result<u64, String> {
                let semantic_id = scene
                    .nodes
                    .values()
                    .find(|node| node.name.as_deref() == Some(name))
                    .map(|node| node.id.clone())
                    .ok_or_else(|| format!("missing semantic node named `{name}`"))?;
                let snapshot = boon_native_app_window::accesskit_tree_update_from_semantic_scene(
                    scene,
                    "boon-native",
                    "verify-accessibility-adapters",
                );
                snapshot
                    .semantic_node_ids
                    .iter()
                    .find(|mapping| mapping.semantic_id == semantic_id.0)
                    .map(|mapping| mapping.accesskit_node_id)
                    .ok_or_else(|| format!("missing AccessKit node for `{name}`"))
            };

            let initial_scene = scene_for_session(&session)?;
            let select_requests = vec![boon_native_app_window::NativeAccessibilityActionRequest {
                target_node_id: node_id_for_name(&initial_scene, "Front-left wheel")?,
                action: boon_native_app_window::NativeAccessibilityAction::Click,
                value: None,
            }];
            let select_report =
            boon_native_app_window::native_accessibility_world_editor_session_reports_from_requests(
                &initial_scene,
                &select_requests,
                &mut session,
                &bundle,
            )
            .into_iter()
            .next()
            .ok_or_else(|| "missing native world editor selection report".to_owned())?;
            if select_report.error.is_some()
                || !select_report
                    .session_report
                    .as_ref()
                    .is_some_and(|report| report.selected_instance_count == 1)
            {
                return Err(format!(
                    "native world editor selection failed: {select_report:?}"
                ));
            }

            let selected_scene = scene_for_session(&session)?;
            let export_requests = vec![boon_native_app_window::NativeAccessibilityActionRequest {
                target_node_id: node_id_for_name(&selected_scene, "Export 3MF")?,
                action: boon_native_app_window::NativeAccessibilityAction::Click,
                value: None,
            }];
            let export_report =
            boon_native_app_window::native_accessibility_world_editor_session_reports_from_requests(
                &selected_scene,
                &export_requests,
                &mut session,
                &bundle,
            )
            .into_iter()
            .next()
            .ok_or_else(|| "missing native world editor export report".to_owned())?;
            let preparation = export_report
                .session_report
                .as_ref()
                .and_then(|report| report.outcome.export_preparation.as_ref())
                .ok_or_else(|| format!("native world editor export failed: {export_report:?}"))?;
            let selected_instance = preparation.selected_instance.ok_or_else(|| {
                "native world editor export did not report selected instance".to_owned()
            })?;
            let print_output = boon_manufacturing::compile_print_job(
                &bundle,
                boon_manufacturing::PrintCompileRequest::for_selected_instances(
                    &bundle,
                    [boon_solid_model::PartInstanceId(selected_instance.0)],
                ),
            );
            let three_mf = boon_3mf::export_3mf_entry_set(&print_output);
            let validation = boon_3mf::validate_3mf_package(&three_mf);
            Ok(NativeWorldEditorSessionProof {
                selected_instance_count: session.scene.metrics().selected_instance_count,
                export_status: format!("{:?}", preparation.status),
                selected_printable: preparation.selected_part_exportable,
                three_mf_status: format!("{:?}", three_mf.status),
                three_mf_validation_status: format!("{:?}", validation.status),
                three_mf_opc_zip_byte_count: three_mf.metrics.opc_zip_byte_count,
                three_mf_entry_count: three_mf.metrics.entry_count,
                three_mf_component_count: three_mf.metrics.component_count,
                three_mf_slice_count: three_mf.metrics.slice_count,
                print_printable_instance_count: print_output.metrics.printable_instance_count,
                visual_mesh_used_for_manufacturing: print_output.visual_mesh_used_for_manufacturing
                    || three_mf.visual_mesh_used_for_manufacturing,
            })
        })();
    let native_world_editor_session_ok =
        native_world_editor_session_result
            .as_ref()
            .is_ok_and(|proof| {
                proof.selected_instance_count == 1
                    && proof.export_status == "ReadySelectedPrintable"
                    && proof.selected_printable
                    && proof.three_mf_status == "Pass"
                    && proof.three_mf_validation_status == "Pass"
                    && proof.three_mf_opc_zip_byte_count > 0
                    && proof.print_printable_instance_count == 1
                    && !proof.visual_mesh_used_for_manufacturing
            });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "accessibility-adapters:native-world-editor-session-actions",
        native_world_editor_session_ok,
        format!("native_world_editor_session_result={native_world_editor_session_result:?}"),
        (!native_world_editor_session_ok).then(|| {
            "native AccessKit action requests must drive WorldEditorSession selection and selected printable export preparation"
                .to_owned()
        }),
    );

    let report = report_arg(args)
        .unwrap_or_else(|| PathBuf::from("target/reports/unified/accessibility-adapters.json"));
    write_static_gate_report(
        args,
        "verify-accessibility-adapters",
        report,
        checks,
        blockers,
        json!({
            "semantic_scene_node_count": scene.nodes.len(),
            "semantic_dom_node_count": dom_snapshot.metrics.dom_node_count,
            "semantic_dom_text_input_endpoint_count": dom_snapshot.metrics.text_input_endpoint_count,
            "semantic_dom_visual_node_count": dom_snapshot.metrics.visual_dom_node_count,
            "semantic_web_ime_endpoint_count": web_bridge.metrics.ime_endpoint_count,
            "semantic_web_action_route_count": web_bridge.metrics.action_route_count,
            "semantic_web_source_routed_action_count": web_bridge.metrics.source_routed_action_count,
            "native_accesskit_node_count": native_snapshot.metrics.accesskit_node_count,
            "native_accesskit_interactive_node_count": native_snapshot.metrics.interactive_node_count,
            "native_accesskit_focusable_node_count": native_snapshot.metrics.focusable_node_count,
            "native_accesskit_text_input_node_count": native_snapshot.metrics.text_input_node_count,
            "native_accesskit_checked_node_count": native_snapshot.metrics.checked_node_count,
            "native_accesskit_node_id_collision_count": native_snapshot.metrics.node_id_collision_count,
            "native_accesskit_tree_update_status": "implemented",
            "native_accessibility_live_tree_delivery_status": "implemented",
            "native_accessibility_live_handler_status": "tree-delivery-and-action-capture-implemented",
            "native_accessibility_action_capture_status": "implemented",
            "native_accessibility_action_routing_status": "focus-click-text-source-intent-routing-implemented",
            "native_accessibility_world_editor_session_action_status": if native_world_editor_session_ok { "world-editor-session-source-actions" } else { "missing-world-editor-session-source-actions" },
            "native_accessibility_world_editor_session_selected_instance_count": native_world_editor_session_result.as_ref().map(|proof| proof.selected_instance_count).unwrap_or(0),
            "native_accessibility_world_editor_session_export_status": native_world_editor_session_result.as_ref().map(|proof| proof.export_status.clone()).unwrap_or_else(|_| "missing".to_owned()),
            "native_accessibility_world_editor_session_export_selected_printable": native_world_editor_session_result.as_ref().map(|proof| proof.selected_printable).unwrap_or(false),
            "native_accessibility_world_editor_session_three_mf_status": native_world_editor_session_result.as_ref().map(|proof| proof.three_mf_status.clone()).unwrap_or_else(|_| "missing".to_owned()),
            "native_accessibility_world_editor_session_three_mf_validation_status": native_world_editor_session_result.as_ref().map(|proof| proof.three_mf_validation_status.clone()).unwrap_or_else(|_| "missing".to_owned()),
            "native_accessibility_world_editor_session_three_mf_opc_zip_byte_count": native_world_editor_session_result.as_ref().map(|proof| proof.three_mf_opc_zip_byte_count).unwrap_or(0),
            "native_accessibility_world_editor_session_three_mf_entry_count": native_world_editor_session_result.as_ref().map(|proof| proof.three_mf_entry_count).unwrap_or(0),
            "native_accessibility_world_editor_session_three_mf_component_count": native_world_editor_session_result.as_ref().map(|proof| proof.three_mf_component_count).unwrap_or(0),
            "native_accessibility_world_editor_session_three_mf_slice_count": native_world_editor_session_result.as_ref().map(|proof| proof.three_mf_slice_count).unwrap_or(0),
            "native_accessibility_world_editor_session_three_mf_printable_instance_count": native_world_editor_session_result.as_ref().map(|proof| proof.print_printable_instance_count).unwrap_or(0),
            "native_accessibility_world_editor_session_three_mf_visual_mesh_used": native_world_editor_session_result.as_ref().map(|proof| proof.visual_mesh_used_for_manufacturing).unwrap_or(true),
            "native_accessibility_world_editor_session_three_mf_scope": "selected-printable-instance-from-export-action",
            "native_playground_world_editor_session_host_status": "host-owns-session-tree-and-routes-native-actions",
            "native_playground_world_editor_visible_panel_status": "visible-document-projected-layout-frame",
            "native_playground_world_editor_visible_input_route_status": "visible-clicks-route-to-world-editor-session",
            "native_playground_world_editor_visible_export_artifact_status": "visible-export-generates-3mf-summary-in-preview-host",
            "web_semantic_static_snapshot_status": "implemented",
            "web_semantic_ime_bridge_status": "live-dom-ime-action-route-contract-implemented",
            "web_host_semantic_bridge_status": web_host_semantic_proof.status,
            "web_host_semantic_bridge_supported_input_events": web_host_semantic_contract.supported_input_events,
            "web_host_semantic_bridge_source_dispatch_count": web_host_semantic_proof.source_dispatch_count,
            "web_host_semantic_bridge_source_routed_action_count": web_host_semantic_proof.source_routed_action_count,
            "web_host_semantic_bridge_supports_increment_dispatch": web_host_semantic_proof.supports_increment_dispatch,
            "web_host_semantic_bridge_supports_decrement_dispatch": web_host_semantic_proof.supports_decrement_dispatch,
            "web_host_semantic_bridge_supports_replace_selected_text_dispatch": web_host_semantic_proof.supports_replace_selected_text_dispatch,
            "web_host_semantic_bridge_visual_dom_node_count": web_host_semantic_proof.visual_dom_node_count,
            "web_host_semantic_bridge_live_function_present": web_host_semantic_proof.live_bridge_function_present,
            "web_host_semantic_bridge_live_mount_present": web_host_semantic_proof.live_bridge_mount_present,
            "web_host_semantic_bridge_live_dispatch_present": web_host_semantic_proof.live_bridge_dispatch_present,
            "web_host_semantic_bridge_live_focus_sync_present": web_host_semantic_proof.live_bridge_focus_sync_present,
            "web_host_semantic_bridge_live_composition_present": web_host_semantic_proof.live_bridge_composition_present,
            "web_live_dom_ime_status": "browser-host-semantic-live-dom-mount-helper-implemented-not-headed-ime-proof",
            "adapter_status": "live-web-semantic-ime-bridge-native-accesskit-tree-update-preview-live-tree-and-action-routing"
        }),
    )
}

fn accessibility_adapter_fixture_scene() -> boon_document::SemanticScene {
    let root_id = boon_document::SemanticId("semantic:root".to_owned());
    let button_id = boon_document::SemanticId("semantic:save".to_owned());
    let checkbox_id = boon_document::SemanticId("semantic:done".to_owned());
    let input_id = boon_document::SemanticId("semantic:filter".to_owned());
    let increment_id = boon_document::SemanticId("semantic:zoom-in".to_owned());
    let decrement_id = boon_document::SemanticId("semantic:zoom-out".to_owned());
    let mut scene = boon_document::SemanticScene {
        root: Some(root_id.clone()),
        focused: Some(input_id.clone()),
        ..boon_document::SemanticScene::default()
    };
    scene.nodes.insert(
        root_id.clone(),
        boon_document::SemanticNode {
            id: root_id.clone(),
            node: boon_document::DocumentNodeId("root".to_owned()),
            role: boon_document::SemanticRole::Application,
            name: Some("Boon app".to_owned()),
            description: None,
            value: None,
            state: boon_document::SemanticState::default(),
            actions: boon_document::SemanticActions::default(),
            relations: boon_document::SemanticRelations {
                children: vec![
                    button_id.clone(),
                    checkbox_id.clone(),
                    input_id.clone(),
                    increment_id.clone(),
                    decrement_id.clone(),
                ],
                ..boon_document::SemanticRelations::default()
            },
            bounds: Some(boon_document::Rect {
                x: 0.0,
                y: 0.0,
                width: 320.0,
                height: 180.0,
            }),
            language: Some("en".to_owned()),
            heading_level: None,
            href: None,
            source_binding_id: None,
            source_path: None,
            source_intent: None,
        },
    );
    scene.nodes.insert(
        button_id.clone(),
        boon_document::SemanticNode {
            id: button_id,
            node: boon_document::DocumentNodeId("save".to_owned()),
            role: boon_document::SemanticRole::Button,
            name: Some("Save".to_owned()),
            description: None,
            value: None,
            state: boon_document::SemanticState::default(),
            actions: boon_document::SemanticActions {
                focus: true,
                press: true,
                set_text: false,
                increment: false,
                decrement: false,
            },
            relations: boon_document::SemanticRelations {
                parent: Some(root_id.clone()),
                ..boon_document::SemanticRelations::default()
            },
            bounds: Some(boon_document::Rect {
                x: 8.0,
                y: 8.0,
                width: 80.0,
                height: 28.0,
            }),
            language: None,
            heading_level: None,
            href: None,
            source_binding_id: Some(boon_document::SourceBindingId("source:save".to_owned())),
            source_path: Some("toolbar.save".to_owned()),
            source_intent: Some("press".to_owned()),
        },
    );
    scene.nodes.insert(
        checkbox_id.clone(),
        boon_document::SemanticNode {
            id: checkbox_id,
            node: boon_document::DocumentNodeId("done".to_owned()),
            role: boon_document::SemanticRole::Checkbox,
            name: Some("Done".to_owned()),
            description: None,
            value: Some(boon_document::SemanticValue::Bool { value: true }),
            state: boon_document::SemanticState {
                checked: Some(true),
                ..boon_document::SemanticState::default()
            },
            actions: boon_document::SemanticActions {
                focus: true,
                press: true,
                set_text: false,
                increment: false,
                decrement: false,
            },
            relations: boon_document::SemanticRelations {
                parent: Some(root_id.clone()),
                ..boon_document::SemanticRelations::default()
            },
            bounds: None,
            language: None,
            heading_level: None,
            href: None,
            source_binding_id: None,
            source_path: None,
            source_intent: None,
        },
    );
    scene.nodes.insert(
        increment_id.clone(),
        boon_document::SemanticNode {
            id: increment_id,
            node: boon_document::DocumentNodeId("zoom-in".to_owned()),
            role: boon_document::SemanticRole::Button,
            name: Some("Zoom in".to_owned()),
            description: None,
            value: Some(boon_document::SemanticValue::Number { value: 1.0 }),
            state: boon_document::SemanticState::default(),
            actions: boon_document::SemanticActions {
                focus: true,
                press: false,
                set_text: false,
                increment: true,
                decrement: false,
            },
            relations: boon_document::SemanticRelations {
                parent: Some(root_id.clone()),
                ..boon_document::SemanticRelations::default()
            },
            bounds: None,
            language: None,
            heading_level: None,
            href: None,
            source_binding_id: Some(boon_document::SourceBindingId(
                "source:zoom:increment".to_owned(),
            )),
            source_path: Some("viewport.zoom".to_owned()),
            source_intent: Some("increment".to_owned()),
        },
    );
    scene.nodes.insert(
        decrement_id.clone(),
        boon_document::SemanticNode {
            id: decrement_id,
            node: boon_document::DocumentNodeId("zoom-out".to_owned()),
            role: boon_document::SemanticRole::Button,
            name: Some("Zoom out".to_owned()),
            description: None,
            value: Some(boon_document::SemanticValue::Number { value: -1.0 }),
            state: boon_document::SemanticState::default(),
            actions: boon_document::SemanticActions {
                focus: true,
                press: false,
                set_text: false,
                increment: false,
                decrement: true,
            },
            relations: boon_document::SemanticRelations {
                parent: Some(root_id.clone()),
                ..boon_document::SemanticRelations::default()
            },
            bounds: None,
            language: None,
            heading_level: None,
            href: None,
            source_binding_id: Some(boon_document::SourceBindingId(
                "source:zoom:decrement".to_owned(),
            )),
            source_path: Some("viewport.zoom".to_owned()),
            source_intent: Some("decrement".to_owned()),
        },
    );
    scene.nodes.insert(
        input_id.clone(),
        boon_document::SemanticNode {
            id: input_id,
            node: boon_document::DocumentNodeId("filter".to_owned()),
            role: boon_document::SemanticRole::TextInput,
            name: Some("Filter".to_owned()),
            description: None,
            value: Some(boon_document::SemanticValue::Text {
                text: "abc".to_owned(),
            }),
            state: boon_document::SemanticState {
                focused: true,
                ..boon_document::SemanticState::default()
            },
            actions: boon_document::SemanticActions {
                focus: true,
                press: false,
                set_text: true,
                increment: false,
                decrement: false,
            },
            relations: boon_document::SemanticRelations {
                parent: Some(root_id),
                ..boon_document::SemanticRelations::default()
            },
            bounds: None,
            language: None,
            heading_level: None,
            href: None,
            source_binding_id: Some(boon_document::SourceBindingId(
                "source:filter:change".to_owned(),
            )),
            source_path: Some("toolbar.filter".to_owned()),
            source_intent: Some("change".to_owned()),
        },
    );
    scene
}

fn verify_native_gpu_layout_contract(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    let mut checks = Vec::new();
    let mut blockers = Vec::new();
    let frame = boon_document::fixture_frame_with_virtualized_table();
    let mut measurer = boon_native_gpu::GlyphonTextMeasurer::new();
    let layout = boon_document::layout(boon_document::LayoutInput {
        document: &frame,
        viewport: boon_host::Viewport {
            surface: 1,
            width: 1280.0,
            height: 900.0,
            scale: 1.0,
        },
        text: &mut measurer,
        capabilities: boon_document::RenderCapabilities::fake_portable(),
    });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:fake-capabilities-no-native-required",
        !layout.metrics.native_capability_required,
        format!(
            "native_capability_required={}",
            layout.metrics.native_capability_required
        ),
        layout
            .metrics
            .native_capability_required
            .then(|| "layout required native-only RenderCapabilities".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:cells-not-expanded-to-2600-widgets",
        layout.metrics.display_item_count < 2600,
        format!("display_item_count={}", layout.metrics.display_item_count),
        (layout.metrics.display_item_count >= 2600)
            .then(|| "Cells layout expanded the full 26x100 logical grid".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:virtualized-demands-present",
        !layout.demands.is_empty(),
        format!("layout demands={}", layout.demands.len()),
        layout
            .demands
            .is_empty()
            .then(|| "Cells fixture did not produce materialization demands".to_owned()),
    );
    let materialization_protocol_complete = !layout.materialization.is_empty()
        && layout.materialization.iter().all(|report| {
            report.logical_item_count >= report.materialized_item_count
                && report.materialized_item_count > 0
                && report.first_stable_key.is_some()
                && report.last_stable_key.is_some()
        })
        && layout.demands.iter().all(|demand| {
            demand.logical_item_count >= demand.materialized_item_count
                && demand.materialized_item_count > 0
                && demand.first_stable_key.is_some()
                && demand.last_stable_key.is_some()
        });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:materialization-protocol-fields",
        materialization_protocol_complete,
        format!(
            "materialization_reports={}, demands={}",
            layout.materialization.len(),
            layout.demands.len()
        ),
        (!materialization_protocol_complete).then(|| {
            "layout materialization reports must include logical/materialized counts and stable key samples".to_owned()
        }),
    );
    let renderer_style_identity_complete = !layout.display_list.is_empty()
        && layout.display_list.iter().all(|item| {
            item.style_identity.style_id != 0
                && item.style_identity.layout_id != 0
                && item.style_identity.paint_id != 0
                && item.style_identity.material_id != 0
                && item.style_identity.font_id != 0
                && item.style_identity.pseudo_state_id != 0
        });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:computed-style-identity-fields",
        renderer_style_identity_complete,
        format!(
            "display_items={}, style_identity_complete={renderer_style_identity_complete}",
            layout.display_list.len()
        ),
        (!renderer_style_identity_complete).then(|| {
            "renderer-facing display items must carry stable style/material/font/pseudo-state IDs"
                .to_owned()
        }),
    );
    let required_invalidation_classes = [
        boon_document::PatchInvalidationClass::PaintOnly,
        boon_document::PatchInvalidationClass::LayoutOnly,
        boon_document::PatchInvalidationClass::HitRegion,
        boon_document::PatchInvalidationClass::SourceBinding,
        boon_document::PatchInvalidationClass::ListStructure,
        boon_document::PatchInvalidationClass::ConditionalStructure,
        boon_document::PatchInvalidationClass::ScrollOffsetOnly,
        boon_document::PatchInvalidationClass::MaterializationOnly,
        boon_document::PatchInvalidationClass::FullDocument,
    ];
    let mut document_state = boon_document::DocumentState::new("root");
    let mut label =
        boon_document::DocumentNode::new("label", boon_document::DocumentNodeKind::Text);
    label.parent = Some(boon_document::DocumentNodeId("root".to_owned()));
    let upsert_report = document_state.apply_patch(boon_document::DocumentPatch::UpsertNode(label));
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:document-patch-upsert-report",
        upsert_report.as_ref().is_ok_and(|report| {
            report.patch_kind == "upsert_node"
                && report
                    .invalidation
                    .contains(&boon_document::PatchInvalidationClass::Structure)
                && report
                    .invalidation
                    .contains(&boon_document::PatchInvalidationClass::Layout)
                && report
                    .invalidation
                    .contains(&boon_document::PatchInvalidationClass::HitRegion)
        }),
        format!("upsert_report={upsert_report:?}"),
        upsert_report
            .as_ref()
            .err()
            .map(|error| format!("document upsert patch failed: {error}")),
    );
    let mut style_patch = boon_document::StylePatch::new();
    style_patch.insert(
        "width".to_owned(),
        Some(boon_document::StyleValue::Number(120.0)),
    );
    style_patch.insert(
        "background_color".to_owned(),
        Some(boon_document::StyleValue::Text("black".to_owned())),
    );
    style_patch.insert(
        "__hover_scope".to_owned(),
        Some(boon_document::StyleValue::Bool(true)),
    );
    style_patch.insert(
        "source_intent".to_owned(),
        Some(boon_document::StyleValue::Text("activate".to_owned())),
    );
    let style_report = document_state.apply_patch(boon_document::DocumentPatch::SetStyle {
        id: boon_document::DocumentNodeId("label".to_owned()),
        patch: style_patch,
    });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:style-patch-computed-invalidation-classes",
        style_report.as_ref().is_ok_and(|report| {
            [
                boon_document::PatchInvalidationClass::Style,
                boon_document::PatchInvalidationClass::PaintOnly,
                boon_document::PatchInvalidationClass::Layout,
                boon_document::PatchInvalidationClass::LayoutOnly,
                boon_document::PatchInvalidationClass::HitRegion,
                boon_document::PatchInvalidationClass::SourceBinding,
                boon_document::PatchInvalidationClass::ConditionalStructure,
            ]
            .iter()
            .all(|class| report.invalidation.contains(class))
        }),
        format!("style_report={style_report:?}"),
        style_report
            .as_ref()
            .err()
            .map(|error| format!("document style patch failed: {error}")),
    );
    let text_report = document_state.apply_patch(boon_document::DocumentPatch::SetText {
        id: boon_document::DocumentNodeId("label".to_owned()),
        text: boon_document::TextValue {
            text: "Patched".to_owned(),
        },
    });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:document-patch-text-report",
        text_report.as_ref().is_ok_and(|report| {
            report.patch_kind == "set_text"
                && report
                    .invalidation
                    .contains(&boon_document::PatchInvalidationClass::Text)
                && report
                    .invalidation
                    .contains(&boon_document::PatchInvalidationClass::Layout)
                && report
                    .invalidation
                    .contains(&boon_document::PatchInvalidationClass::HitRegion)
        }),
        format!("text_report={text_report:?}"),
        text_report
            .as_ref()
            .err()
            .map(|error| format!("document text patch failed: {error}")),
    );
    let missing_error = document_state.apply_patch(boon_document::DocumentPatch::SetStyle {
        id: boon_document::DocumentNodeId("missing".to_owned()),
        patch: boon_document::StylePatch::new(),
    });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:document-patch-missing-target-fails-closed",
        matches!(
            &missing_error,
            Err(boon_document::PatchApplyError::MissingTarget {
                patch_kind: "set_style",
                ..
            })
        ),
        format!("missing_error={missing_error:?}"),
        missing_error.is_ok().then(|| {
            "document patch missing target succeeded instead of failing closed".to_owned()
        }),
    );
    let mut orphan =
        boon_document::DocumentNode::new("orphan-parent", boon_document::DocumentNodeKind::Stack);
    orphan.parent = Some(boon_document::DocumentNodeId("root".to_owned()));
    orphan
        .children
        .push(boon_document::DocumentNodeId("missing-child".to_owned()));
    let orphan_error = document_state.apply_patch(boon_document::DocumentPatch::UpsertNode(orphan));
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:document-patch-orphan-child-fails-closed",
        matches!(
            &orphan_error,
            Err(boon_document::PatchApplyError::OrphanedChild { .. })
        ),
        format!("orphan_error={orphan_error:?}"),
        orphan_error
            .is_ok()
            .then(|| "document patch orphan child succeeded instead of failing closed".to_owned()),
    );
    let remove_report = document_state.apply_patch(boon_document::DocumentPatch::RemoveNode {
        id: boon_document::DocumentNodeId("label".to_owned()),
    });
    let invalidation_vocabulary_complete = upsert_report.as_ref().is_ok_and(|report| {
        required_invalidation_classes
            .iter()
            .filter(|class| report.invalidation.contains(class))
            .count()
            >= 4
    }) && style_report.as_ref().is_ok_and(|report| {
        required_invalidation_classes
            .iter()
            .any(|class| report.invalidation.contains(class))
    }) && text_report.as_ref().is_ok_and(|report| {
        report
            .invalidation
            .contains(&boon_document::PatchInvalidationClass::PaintOnly)
    }) && remove_report.as_ref().is_ok_and(|report| {
        required_invalidation_classes.iter().all(|class| {
            report.invalidation.contains(class)
                || !matches!(
                    class,
                    boon_document::PatchInvalidationClass::ScrollOffsetOnly
                        | boon_document::PatchInvalidationClass::MaterializationOnly
                        | boon_document::PatchInvalidationClass::FullDocument
                )
        })
    });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:expanded-invalidation-vocabulary",
        invalidation_vocabulary_complete,
        format!("required_invalidation_classes={required_invalidation_classes:?}"),
        (!invalidation_vocabulary_complete).then(|| {
            "document patch reports must expose paint/layout/hit/source/list/conditional/scroll/materialization/full-document classes".to_owned()
        }),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "layout-contract:document-patch-remove-report",
        remove_report.as_ref().is_ok_and(|report| {
            report.patch_kind == "remove_node"
                && report.removed_nodes == vec![boon_document::DocumentNodeId("label".to_owned())]
                && report
                    .invalidation
                    .contains(&boon_document::PatchInvalidationClass::Structure)
        }),
        format!("remove_report={remove_report:?}"),
        remove_report
            .as_ref()
            .err()
            .map(|error| format!("document remove patch failed: {error}")),
    );
    write_native_gate_report(
        args,
        "verify-native-gpu-layout-contract",
        checks,
        blockers,
        json!({
            "layout_metrics": layout.metrics,
            "demand_count": layout.demands.len(),
            "layout_demands": layout.demands,
            "layout_materialization": layout.materialization,
            "computed_style_identity_samples": layout
                .display_list
                .iter()
                .take(12)
                .map(|item| json!({
                    "node": item.node,
                    "kind": item.kind,
                    "style_identity": item.style_identity
                }))
                .collect::<Vec<_>>(),
            "document_patch_contract": {
                "structured_apply_report": true,
                "missing_target_fails_closed": true,
                "orphan_child_fails_closed": true,
                "remove_node_subtree_semantics": "explicit_reported_removed_nodes",
                "invalidation_classes": [
                    "structure",
                    "text",
                    "style",
                    "binding",
                    "scroll",
                    "materialization",
                    "layout",
                    "hit_region",
                    "paint_only",
                    "layout_only",
                    "source_binding",
                    "list_structure",
                    "conditional_structure",
                    "scroll_offset_only",
                    "materialization_only",
                    "full_document"
                ]
            }
        }),
    )
}

fn verify_native_gpu_shaders(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    let mut checks = Vec::new();
    let mut blockers = Vec::new();
    let wesl_source = Path::new("shaders/native_gpu_rect.wesl");
    let generated_wgsl = Path::new("crates/boon_native_gpu/src/generated/native_gpu_rect.wgsl");
    let generated_bindings = Path::new("crates/boon_native_gpu/src/generated/shader_bindings.rs");
    let wesl_count = count_files_with_extension(Path::new("shaders"), "wesl")?;
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:wesl-inputs-present",
        wesl_count > 0,
        format!("{wesl_count} WESL shader inputs found"),
        (wesl_count == 0).then(|| "missing shaders/*.wesl inputs for native GPU path".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:rect-wesl-source-present",
        wesl_source.exists(),
        format!("{} exists={}", wesl_source.display(), wesl_source.exists()),
        (!wesl_source.exists()).then(|| {
            format!(
                "missing native GPU WESL source artifact `{}`",
                wesl_source.display()
            )
        }),
    );
    let generated_wgsl_text = std::fs::read_to_string(generated_wgsl).unwrap_or_default();
    let wesl_text = std::fs::read_to_string(wesl_source).unwrap_or_default();
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:generated-wgsl-output-present",
        generated_wgsl.exists(),
        format!(
            "{} exists={}",
            generated_wgsl.display(),
            generated_wgsl.exists()
        ),
        (!generated_wgsl.exists()).then(|| {
            format!(
                "missing generated WGSL artifact `{}`",
                generated_wgsl.display()
            )
        }),
    );
    let generated_wgsl_fresh = generated_wgsl.exists()
        && wesl_source.exists()
        && file_hash(&generated_wgsl.display().to_string())
            == file_hash(&wesl_source.display().to_string())
        && generated_wgsl_text == wesl_text;
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:generated-wgsl-fresh",
        generated_wgsl_fresh,
        format!("generated WGSL mirrors current WESL source={generated_wgsl_fresh}"),
        (!generated_wgsl_fresh)
            .then(|| "generated WGSL is stale; run `cargo xtask shaders`".to_owned()),
    );
    let generated_text = std::fs::read_to_string(generated_bindings).unwrap_or_default();
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:wgsl-bindgen-output-present",
        generated_bindings.exists(),
        format!(
            "{} exists={}",
            generated_bindings.display(),
            generated_bindings.exists()
        ),
        (!generated_bindings.exists()).then(|| {
            format!(
                "missing generated shader binding artifact `{}`",
                generated_bindings.display()
            )
        }),
    );
    let generated_marker_ok = generated_text.contains("WGSL_BINDGEN_GENERATED: bool = true")
        && generated_text.contains("SHADER_BINDING_GENERATOR: &str = \"wgsl_bindgen\"")
        && generated_text.contains("create_shader_module_embed_source")
        && generated_text.contains("vertex_state")
        && generated_text.contains("fragment_state")
        && generated_text.contains("vs_main_entry")
        && generated_text.contains("fs_main_entry");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:wgsl-bindgen-api",
        generated_marker_ok,
        "generated bindings expose a wgsl_bindgen Rust API, not only provenance markers",
        (!generated_marker_ok).then(|| {
            "generated shader bindings are not real wgsl_bindgen Rust APIs yet".to_owned()
        }),
    );
    let wesl_hash = file_hash(&wesl_source.display().to_string());
    let generated_wgsl_hash = file_hash(&generated_wgsl.display().to_string());
    let hash_fresh = generated_text.contains(&wesl_hash);
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:generated-hash-fresh",
        hash_fresh,
        format!("generated hash matches shaders/native_gpu_rect.wesl={hash_fresh}"),
        (!hash_fresh)
            .then(|| "generated shader bindings are stale; run `cargo xtask shaders`".to_owned()),
    );
    let renderer_source = std::fs::read_to_string("crates/boon_native_gpu/src/lib.rs")?;
    let renderer_uses_generated_api =
        renderer_source.contains("generated::shader_bindings::ShaderEntry");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:renderer-uses-generated-api",
        renderer_uses_generated_api,
        format!("renderer uses generated shader API={renderer_uses_generated_api}"),
        (!renderer_uses_generated_api)
            .then(|| "boon_native_gpu does not consume generated shader API".to_owned()),
    );
    let bypasses_generated = renderer_source.contains("include_str!")
        || renderer_source.contains("ShaderSource::Wgsl")
        || renderer_source.contains("native_gpu_rect.wgsl")
        || renderer_source.contains("create_shader_module(")
        || renderer_source.contains("ShaderModuleDescriptor");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:no-manual-wgsl-loading",
        !bypasses_generated,
        format!("renderer manual shader loading markers present={bypasses_generated}"),
        bypasses_generated.then(|| {
            "boon_native_gpu bypasses generated shader bindings with manual WGSL loading".to_owned()
        }),
    );
    let duplicate_layouts = renderer_source.contains("device.create_pipeline_layout(")
        || renderer_source.contains("request.device.create_pipeline_layout(")
        || renderer_source.contains(".create_bind_group_layout(");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:no-duplicate-manual-layouts",
        !duplicate_layouts,
        format!("renderer duplicate manual layout construction markers present={duplicate_layouts}"),
        duplicate_layouts.then(|| {
            "boon_native_gpu constructs duplicate manual bind group or pipeline layouts outside generated bindings".to_owned()
        }),
    );
    let manual_entry_points = renderer_source.contains("entry_point: Some(\"")
        || renderer_source.contains("ENTRY_VS_MAIN")
        || renderer_source.contains("ENTRY_FS_MAIN")
        || renderer_source.contains("\"vs_main\"")
        || renderer_source.contains("\"fs_main\"");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:no-manual-entry-points",
        !manual_entry_points,
        format!("renderer manual entry-point markers present={manual_entry_points}"),
        manual_entry_points.then(|| {
            "boon_native_gpu duplicates shader entry-point definitions outside generated bindings".to_owned()
        }),
    );
    let vertex_layout_contract = boon_native_gpu::native_gpu_quad_vertex_layout_contract();
    let expected_vertex_attributes = json!([
        {
            "shader_location": 0,
            "offset": 0,
            "format": "Float32x2"
        },
        {
            "shader_location": 1,
            "offset": 8,
            "format": "Uint32"
        },
        {
            "shader_location": 2,
            "offset": 12,
            "format": "Float32x2"
        }
    ]);
    let expected_generated_shader_inputs = json!([
        {
            "shader_location": 0,
            "format": "Float32x2"
        },
        {
            "shader_location": 1,
            "format": "Uint32"
        },
        {
            "shader_location": 2,
            "format": "Float32x2"
        }
    ]);
    let host_pod_layout_ok = vertex_layout_contract
        .get("pod")
        .and_then(serde_json::Value::as_bool)
        == Some(true)
        && vertex_layout_contract
            .get("size")
            .and_then(serde_json::Value::as_u64)
            == Some(20)
        && vertex_layout_contract
            .get("align")
            .and_then(serde_json::Value::as_u64)
            == Some(4)
        && vertex_layout_contract
            .get("buffer_count")
            .and_then(serde_json::Value::as_u64)
            == Some(1)
        && vertex_layout_contract
            .get("array_stride")
            .and_then(serde_json::Value::as_u64)
            == Some(20)
        && vertex_layout_contract
            .get("step_mode")
            .and_then(serde_json::Value::as_str)
            == Some("Vertex")
        && vertex_layout_contract.get("attributes") == Some(&expected_vertex_attributes);
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:host-pod-layout",
        host_pod_layout_ok,
        format!("host POD vertex layout contract={vertex_layout_contract}"),
        (!host_pod_layout_ok).then(|| {
            "native GPU host POD vertex layout does not match expected shader ABI".to_owned()
        }),
    );
    let generated_layout_ok = vertex_layout_contract.get("generated_shader_inputs")
        == Some(&expected_generated_shader_inputs);
    push_audit_check(
        &mut checks,
        &mut blockers,
        "shaders:generated-vertex-attributes",
        generated_layout_ok,
        format!(
            "generated shader inputs={}",
            vertex_layout_contract
                .get("generated_shader_inputs")
                .cloned()
                .unwrap_or_else(|| json!(null))
        ),
        (!generated_layout_ok).then(|| {
            "generated shader attributes no longer match the renderer POD vertex layout".to_owned()
        }),
    );
    let shader_outputs_fresh = generated_wgsl_fresh && hash_fresh && generated_marker_ok;
    let mut artifact_sha256s = Vec::new();
    if generated_wgsl.exists() {
        artifact_sha256s.push(artifact_hash(generated_wgsl)?);
    }
    if generated_bindings.exists() {
        artifact_sha256s.push(artifact_hash(generated_bindings)?);
    }
    write_native_gate_report(
        args,
        "verify-native-gpu-shaders",
        checks,
        blockers,
        json!({
            "source_hash": wesl_hash,
            "expected_source_hash": wesl_hash,
            "shader_outputs_fresh": shader_outputs_fresh,
            "shader_source_path": wesl_source.display().to_string(),
            "generated_wgsl": generated_wgsl.display().to_string(),
            "generated_shader_bindings": generated_bindings.display().to_string(),
            "generated_wgsl_hash": generated_wgsl_hash,
            "vertex_layout_contract": vertex_layout_contract,
            "artifact_sha256s": artifact_sha256s,
            "renderer_static_checks": {
                "uses_generated_api": renderer_uses_generated_api,
                "manual_wgsl_loading": bypasses_generated,
                "duplicate_manual_layouts": duplicate_layouts,
                "manual_entry_points": manual_entry_points
            }
        }),
    )
}

fn generate_native_gpu_shader_bindings(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    let source = Path::new("shaders/native_gpu_rect.wesl");
    let generated_dir = Path::new("crates/boon_native_gpu/src/generated");
    let generated = generated_dir.join("shader_bindings.rs");
    let wgsl_output = generated_dir.join("native_gpu_rect.wgsl");
    let source_text = std::fs::read_to_string(source)?;
    let source_hash = boon_runtime::sha256_file(source)?;
    std::fs::create_dir_all(generated_dir)?;
    std::fs::write(&wgsl_output, &source_text)?;
    let _ = std::fs::remove_file(&generated);
    wgsl_bindgen::WgslBindgenOptionBuilder::default()
        .workspace_root(generated_dir)
        .add_entry_point(wgsl_output.display().to_string())
        .serialization_strategy(wgsl_bindgen::WgslTypeSerializeStrategy::Encase)
        .skip_hash_check(true)
        .output(&generated)
        .build()?
        .generate()?;
    prepend_native_gpu_shader_metadata(&generated, source_hash.as_str())?;
    let rustfmt_status = Command::new("rustfmt").arg(&generated).status()?;
    if !rustfmt_status.success() {
        return Err(format!("rustfmt failed for `{}`", generated.display()).into());
    }
    if let Some(report) = report_arg(args) {
        let report_json = json!({
            "status": "pass",
            "report_version": 1,
            "generated_at_utc": current_unix_seconds().to_string(),
            "command": "shaders",
            "command_argv": args,
            "measurement_mode": "proof",
            "exit_status": 0,
            "git_commit": git_commit(),
            "binary_hash": current_binary_hash(),
            "source_path": source.display().to_string(),
            "source_hash": source_hash,
            "scenario_hash": "n/a",
            "program_hash": "n/a",
            "budget_hash": file_hash("budgets/native-gpu.toml"),
            "graph_node_count": 0,
            "per_step_pass_fail": [
                {"id": "wesl-input-read", "pass": true},
                {"id": "wesl-to-wgsl-written", "pass": true},
                {"id": "wgsl-bindgen-rust-api-written", "pass": true}
            ],
            "artifact_sha256s": [artifact_hash(&wgsl_output)?, artifact_hash(&generated)?],
            "generated_wgsl": wgsl_output.display().to_string(),
            "generated_shader_bindings": generated.display().to_string()
        });
        write_json(&report, &report_json)?;
        verify_report_schema(&report)?;
    }
    println!("wrote {}", generated.display());
    Ok(())
}

fn prepend_native_gpu_shader_metadata(
    generated: &Path,
    source_hash: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    let generated_text = std::fs::read_to_string(generated)?;
    let metadata = format!(
        r#"// Generated by `cargo xtask shaders`.
// Source pipeline: shaders/*.wesl -> generated WGSL -> wgsl_bindgen Rust API.

pub const WGSL_BINDGEN_GENERATED: bool = true;
pub const SHADER_SOURCE_KIND: &str = "wesl";
pub const SHADER_BINDING_GENERATOR: &str = "wgsl_bindgen";
pub const NATIVE_GPU_RECT_WESL_SHA256: &str = "{source_hash}";

"#
    );
    let mut output = String::new();
    let mut inserted = false;
    for line in generated_text.lines() {
        output.push_str(line);
        output.push('\n');
        if !inserted && line.trim_start().starts_with("#![allow(") {
            output.push_str(&metadata);
            inserted = true;
        }
    }
    if !inserted {
        output = format!("{metadata}{generated_text}");
    }
    std::fs::write(generated, output)?;
    Ok(())
}

fn verify_native_gpu_multiwindow(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    let mut checks = Vec::new();
    let mut blockers = Vec::new();
    let supervisor_report = PathBuf::from("target/reports/native-gpu/.multiwindow-supervisor.json");
    let live_state_report =
        PathBuf::from("target/artifacts/native-gpu/multiwindow-live-state.json");
    let mut cosmic_launch_proof = json!({"status": "not-run"});
    let prefer_isolated_real_window = std::env::var("BOON_NATIVE_GPU_PREVIEW_E2E_ISOLATED")
        .ok()
        .as_deref()
        == Some("1");
    let mut isolated_real_window_launch_proof = json!({
        "status": "not-run",
        "reason": if prefer_isolated_real_window {
            "isolated Weston launch unavailable or not applicable"
        } else {
            "workspace-qualified COSMIC launch is the default scroll-speed path"
        }
    });
    let _ = std::fs::remove_file(&supervisor_report);
    let _ = std::fs::remove_file(&live_state_report);
    let _ = std::fs::remove_file("target/reports/native-gpu/.multiwindow-live-state.json");
    let wayland = std::env::var_os("WAYLAND_DISPLAY").is_some()
        && std::env::var("XDG_SESSION_TYPE").unwrap_or_default() == "wayland";
    let isolated_real_window_available = command_available("weston")
        && command_available("wayland-info")
        && weston_test_plugin_path().is_some()
        && weston_test_driver_path().is_some();
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-multiwindow:isolated-real-window-environment",
        isolated_real_window_available,
        format!(
            "WAYLAND_DISPLAY={:?}, XDG_SESSION_TYPE={:?}, isolated_real_window_available={isolated_real_window_available}",
            std::env::var("WAYLAND_DISPLAY").ok(),
            std::env::var("XDG_SESSION_TYPE").ok()
        ),
        (!isolated_real_window_available).then(|| {
            "native multiwindow proof requires the isolated Weston real-window harness".to_owned()
        }),
    );

    let build = Command::new("cargo")
        .args(["build", "-p", "boon_native_playground"])
        .status()?;
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-multiwindow:playground-build",
        build.success(),
        format!("cargo build -p boon_native_playground status={build}"),
        (!build.success()).then(|| "failed to build boon_native_playground".to_owned()),
    );

    if build.success() && isolated_real_window_available {
        isolated_real_window_launch_proof = run_isolated_weston_desktop_preview_e2e(
            Path::new("target/debug/boon_native_playground"),
            "todomvc",
            &native_gpu_title_token("multiwindow"),
            1_500,
            60_000,
            &supervisor_report,
            &live_state_report,
            None,
            Some("a"),
            None,
            true,
            false,
            false,
        )?;
        let launch_success = isolated_real_window_launch_proof
            .get("status")
            .and_then(serde_json::Value::as_str)
            == Some("pass");
        push_audit_check(
            &mut checks,
            &mut blockers,
            "native-gpu-multiwindow:isolated-launch-command",
            launch_success,
            format!(
                "status={:?}, desktop_pass={:?}, driver_effect_observed={:?}",
                isolated_real_window_launch_proof
                    .get("status")
                    .and_then(serde_json::Value::as_str),
                isolated_real_window_launch_proof
                    .get("desktop_pass")
                    .and_then(serde_json::Value::as_bool),
                isolated_real_window_launch_proof
                    .get("driver_effect_observed")
                    .and_then(serde_json::Value::as_bool)
            ),
            (!launch_success).then(|| {
                "isolated native multiwindow launch failed to produce real-window proof".to_owned()
            }),
        );
        let live_state_ready = live_state_report.exists();
        push_audit_check(
            &mut checks,
            &mut blockers,
            "native-gpu-multiwindow:live-state-report-written",
            live_state_ready,
            format!("{} ready={live_state_ready}", live_state_report.display()),
            (!live_state_ready).then(|| {
                format!(
                    "desktop supervisor did not write live state `{}` while windows were alive",
                    live_state_report.display()
                )
            }),
        );
        let report_ready = supervisor_report.exists();
        push_audit_check(
            &mut checks,
            &mut blockers,
            "native-gpu-multiwindow:supervisor-report-written",
            report_ready,
            format!("{} ready={report_ready}", supervisor_report.display()),
            (!report_ready).then(|| {
                format!(
                    "desktop supervisor did not write `{}`",
                    supervisor_report.display()
                )
            }),
        );
    } else if false && build.success() && wayland {
        let launcher_available = command_available("cosmic-background-launch");
        push_audit_check(
            &mut checks,
            &mut blockers,
            "native-gpu-multiwindow:cosmic-background-launch-available",
            launcher_available,
            format!("cosmic-background-launch available={launcher_available}"),
            (!launcher_available).then(|| {
                "cosmic-background-launch is required for COSMIC workspace-qualified proof"
                    .to_owned()
            }),
        );
        if launcher_available {
            let cwd = std::env::current_dir()?;
            let script = format!(
                "cd {} && ./target/debug/boon_native_playground --role desktop --example cells --probe --child-hold-ms 10000 --dev-hold-ms 5000 --role-report-timeout-ms 60000 --live-state-report {} --report {} >>/tmp/boon-native-gpu-multiwindow.log 2>&1",
                shell_quote(&cwd.display().to_string()),
                shell_quote(&live_state_report.display().to_string()),
                shell_quote(&supervisor_report.display().to_string())
            );
            cosmic_launch_proof = run_cosmic_background_launch("boon-circuit", &script)?;
            let launch_success = cosmic_launch_proof
                .get("success")
                .and_then(serde_json::Value::as_bool)
                == Some(true);
            let launch_machine_readable = cosmic_launch_proof
                .get("child_pid")
                .and_then(serde_json::Value::as_u64)
                .is_some()
                && cosmic_launch_proof
                    .get("launch_id")
                    .and_then(serde_json::Value::as_str)
                    .is_some_and(|id| id.starts_with("background-launch-"));
            push_audit_check(
                &mut checks,
                &mut blockers,
                "native-gpu-multiwindow:cosmic-launch-command",
                launch_success,
                format!(
                    "cosmic-background-launch status={:?}, stdout={:?}",
                    cosmic_launch_proof
                        .get("exit_status")
                        .and_then(serde_json::Value::as_str),
                    cosmic_launch_proof
                        .get("stdout")
                        .and_then(serde_json::Value::as_str)
                ),
                (!launch_success).then(|| "cosmic-background-launch failed".to_owned()),
            );
            push_audit_check(
                &mut checks,
                &mut blockers,
                "native-gpu-multiwindow:cosmic-launch-machine-readable-stdout",
                launch_machine_readable,
                format!(
                    "child_pid={:?}, launch_id={:?}",
                    cosmic_launch_proof
                        .get("child_pid")
                        .and_then(serde_json::Value::as_u64),
                    cosmic_launch_proof
                        .get("launch_id")
                        .and_then(serde_json::Value::as_str)
                ),
                (!launch_machine_readable).then(|| {
                    "cosmic-background-launch did not print parseable pid/launch id".to_owned()
                }),
            );
            if launch_success {
                let live_state_ready =
                    wait_for_json_report(&live_state_report, Duration::from_secs(80));
                push_audit_check(
                    &mut checks,
                    &mut blockers,
                    "native-gpu-multiwindow:live-state-report-written",
                    live_state_ready,
                    format!("{} ready={live_state_ready}", live_state_report.display()),
                    (!live_state_ready).then(|| {
                        format!(
                            "desktop supervisor did not write live state `{}` while windows were alive",
                            live_state_report.display()
                        )
                    }),
                );
                if live_state_ready {
                    let live_state = read_json(&live_state_report)?;
                    let preview_pid = live_state
                        .get("preview_child_pid")
                        .and_then(serde_json::Value::as_u64)
                        .is_some_and(|pid| pid > 0);
                    let dev_pid = live_state
                        .get("dev_child_pid")
                        .and_then(serde_json::Value::as_u64)
                        .is_some_and(|pid| pid > 0);
                    let child_process_proof = preview_pid && dev_pid;
                    push_audit_check(
                        &mut checks,
                        &mut blockers,
                        "native-gpu-multiwindow:live-child-process-proof",
                        child_process_proof,
                        format!("preview_child_pid={preview_pid}, dev_child_pid={dev_pid}"),
                        (!child_process_proof).then(|| {
                            "desktop supervisor did not report both native child process ids"
                                .to_owned()
                        }),
                    );
                }
                let report_ready =
                    wait_for_json_report(&supervisor_report, Duration::from_secs(80));
                push_audit_check(
                    &mut checks,
                    &mut blockers,
                    "native-gpu-multiwindow:supervisor-report-written",
                    report_ready,
                    format!("{} ready={report_ready}", supervisor_report.display()),
                    (!report_ready).then(|| {
                        format!(
                            "desktop supervisor did not write `{}`",
                            supervisor_report.display()
                        )
                    }),
                );
            }
        }
    }

    let mut extra = json!({
        "requested_workspace": "boon-circuit",
        "launcher_command": "isolated-weston-headless-with-weston-test-control",
        "cosmic_background_launch_proof": cosmic_launch_proof,
        "isolated_real_window_launch_proof": isolated_real_window_launch_proof,
        "cosmic_toplevel_probe": {"status": "removed", "reason": "native proof uses app-owned live state and process reports, not compositor toplevel scraping"},
        "supervisor_report": supervisor_report,
        "live_state_report": live_state_report,
    });
    if live_state_report.exists() {
        let live_state = read_json(&live_state_report)?;
        if let Some(object) = live_state.as_object() {
            for key in [
                "title_token",
                "preview_window_title",
                "dev_window_title",
                "preview_child_pid",
                "dev_child_pid",
                "preview_child_cmdline",
                "dev_child_cmdline",
                "display_server",
                "display_connection",
            ] {
                if let Some(value) = object.get(key) {
                    extra[key] = value.clone();
                }
            }
        }
        extra["live_state_report_sha256"] =
            json!(file_hash(live_state_report.to_string_lossy().as_ref()));
    }
    if supervisor_report.exists() {
        let supervisor = read_json(&supervisor_report)?;
        if let Some(object) = supervisor.as_object() {
            for key in [
                "process_model",
                "preview_child_pid",
                "dev_child_pid",
                "preview_child_cmdline",
                "dev_child_cmdline",
                "preview_survives_dev_exit",
                "dev_exit_status",
                "preview_clean_exit_after_dev_exit",
                "preview_exit_status_after_dev_exit",
                "preview_receives_example_name",
                "title_token",
                "preview_window_title",
                "dev_window_title",
                "display_server",
                "display_connection",
                "dev_ipc_probe",
                "preview_document_layout_proof",
                "preview_runtime_summary",
                "preview_native_gpu_render_proof",
                "preview_surface_proof",
                "dev_surface_proof",
                "preview_role_report",
                "dev_role_report",
                "preview_role_report_sha256",
                "dev_role_report_sha256",
                "cosmic_background_launch_machine_readable_proof",
                "note",
            ] {
                if let Some(value) = object.get(key) {
                    extra[key] = value.clone();
                }
            }
            if let Some(supervisor_blockers) = supervisor
                .get("blockers")
                .and_then(serde_json::Value::as_array)
            {
                for blocker in supervisor_blockers {
                    if let Some(blocker) = blocker.as_str() {
                        blockers.push(blocker.to_owned());
                    }
                }
            }
        }
        push_audit_check(
            &mut checks,
            &mut blockers,
            "native-gpu-multiwindow:supervisor-status-pass",
            supervisor.get("status").and_then(serde_json::Value::as_str) == Some("pass"),
            format!(
                "{} status={:?}",
                supervisor_report.display(),
                supervisor.get("status").and_then(serde_json::Value::as_str)
            ),
            (supervisor.get("status").and_then(serde_json::Value::as_str) != Some("pass"))
                .then(|| "desktop supervisor still reports blockers".to_owned()),
        );
    }
    let preview_pid = extra
        .get("preview_child_pid")
        .and_then(serde_json::Value::as_u64);
    let dev_pid = extra
        .get("dev_child_pid")
        .and_then(serde_json::Value::as_u64);
    let preview_surface_id = extra
        .pointer("/preview_surface_proof/surface_id")
        .and_then(serde_json::Value::as_str);
    let dev_surface_id = extra
        .pointer("/dev_surface_proof/surface_id")
        .and_then(serde_json::Value::as_str);
    let independent_processes = preview_pid.zip(dev_pid).is_some_and(|(left, right)| {
        left > 0
            && right > 0
            && left != right
            && extra
                .pointer("/preview_surface_proof/pid")
                .and_then(serde_json::Value::as_u64)
                == Some(left)
            && extra
                .pointer("/dev_surface_proof/pid")
                .and_then(serde_json::Value::as_u64)
                == Some(right)
    });
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-multiwindow:independent-child-process-identities",
        independent_processes,
        format!(
            "preview_pid={preview_pid:?}, dev_pid={dev_pid:?}, preview_surface_pid={:?}, dev_surface_pid={:?}",
            extra
                .pointer("/preview_surface_proof/pid")
                .and_then(serde_json::Value::as_u64),
            extra
                .pointer("/dev_surface_proof/pid")
                .and_then(serde_json::Value::as_u64)
        ),
        (!independent_processes).then(|| {
            "preview/dev child PID and surface PID identities are not independent".to_owned()
        }),
    );
    let independent_surfaces = preview_surface_id
        .zip(dev_surface_id)
        .is_some_and(|(left, right)| !left.is_empty() && !right.is_empty() && left != right);
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-multiwindow:independent-window-surface-identities",
        independent_surfaces,
        format!("preview_surface_id={preview_surface_id:?}, dev_surface_id={dev_surface_id:?}"),
        (!independent_surfaces).then(|| {
            "preview/dev app_window or WGPU surface identities are not independent".to_owned()
        }),
    );
    let both_presented = extra
        .pointer("/preview_surface_proof/presented_frame")
        .and_then(serde_json::Value::as_bool)
        == Some(true)
        && extra
            .pointer("/dev_surface_proof/presented_frame")
            .and_then(serde_json::Value::as_bool)
            == Some(true)
        && extra
            .pointer("/preview_native_gpu_render_proof/status")
            .and_then(serde_json::Value::as_str)
            == Some("pass");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-multiwindow:preview-dev-presented-nonblank-frames",
        both_presented,
        format!(
            "preview_presented={:?}, dev_presented={:?}, native_render_status={:?}",
            extra
                .pointer("/preview_surface_proof/presented_frame")
                .and_then(serde_json::Value::as_bool),
            extra
                .pointer("/dev_surface_proof/presented_frame")
                .and_then(serde_json::Value::as_bool),
            extra
                .pointer("/preview_native_gpu_render_proof/status")
                .and_then(serde_json::Value::as_str)
        ),
        (!both_presented).then(|| {
            "preview/dev surfaces did not both present with app-owned render proof".to_owned()
        }),
    );
    let preview_clean_exit = extra
        .get("preview_clean_exit_after_dev_exit")
        .and_then(serde_json::Value::as_bool)
        == Some(true);
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-multiwindow:preview-clean-exit-after-dev-exit",
        preview_clean_exit,
        format!(
            "preview_clean_exit_after_dev_exit={:?}, preview_exit_status_after_dev_exit={:?}, dev_exit_status={:?}",
            extra
                .get("preview_clean_exit_after_dev_exit")
                .and_then(serde_json::Value::as_bool),
            extra
                .get("preview_exit_status_after_dev_exit")
                .and_then(serde_json::Value::as_str),
            extra
                .get("dev_exit_status")
                .and_then(serde_json::Value::as_str)
        ),
        (!preview_clean_exit)
            .then(|| "preview role did not exit cleanly after the dev role exited".to_owned()),
    );
    let replace_code_ok = native_gpu_replace_code_evidence_ok(&extra, "/dev_ipc_probe");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-multiwindow:dev-replace-code-command",
        replace_code_ok,
        format!(
            "dev_sent_replace_code={:?}, preview_command={:?}, hash_matches={:?}",
            extra
                .pointer("/dev_ipc_probe/dev_sent_replace_code")
                .and_then(serde_json::Value::as_bool),
            extra
                .pointer("/dev_ipc_probe/replace_code/preview_command")
                .and_then(serde_json::Value::as_str),
            extra
                .pointer("/dev_ipc_probe/replace_code/hash_matches")
                .and_then(serde_json::Value::as_bool)
        ),
        (!replace_code_ok).then(|| {
            "dev role did not prove a bounded ReplaceCode command accepted by preview".to_owned()
        }),
    );

    write_native_gate_report(
        args,
        "verify-native-gpu-multiwindow",
        checks,
        blockers,
        extra,
    )
}

fn verify_native_gpu_ipc_backpressure(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    let mut checks = Vec::new();
    let mut blockers = Vec::new();
    let queue_capacity = native_gpu_budget_u64("ipc", "queue_depth_max").unwrap_or(256);
    let supervisor_report = PathBuf::from("target/reports/native-gpu/.ipc-supervisor.json");
    let live_state_report = PathBuf::from("target/artifacts/native-gpu/ipc-live-state.json");
    let _ = std::fs::remove_file(&supervisor_report);
    let _ = std::fs::remove_file(&live_state_report);
    let wayland = std::env::var_os("WAYLAND_DISPLAY").is_some()
        && std::env::var("XDG_SESSION_TYPE").unwrap_or_default() == "wayland";
    let isolated_real_window_available = command_available("weston")
        && command_available("wayland-info")
        && weston_test_plugin_path().is_some()
        && weston_test_driver_path().is_some();
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:isolated-real-window-environment",
        isolated_real_window_available,
        format!(
            "WAYLAND_DISPLAY={:?}, XDG_SESSION_TYPE={:?}, isolated_real_window_available={isolated_real_window_available}",
            std::env::var("WAYLAND_DISPLAY").ok(),
            std::env::var("XDG_SESSION_TYPE").ok()
        ),
        (!isolated_real_window_available).then(|| {
            "native IPC proof requires the isolated Weston real-window harness".to_owned()
        }),
    );

    let build = Command::new("cargo")
        .args(["build", "-p", "boon_native_playground"])
        .status()?;
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:playground-build",
        build.success(),
        format!("cargo build -p boon_native_playground status={build}"),
        (!build.success()).then(|| "failed to build boon_native_playground".to_owned()),
    );

    let mut isolated_real_window_launch_proof = json!({"status": "not-run"});
    if build.success() && isolated_real_window_available {
        isolated_real_window_launch_proof = run_isolated_weston_desktop_preview_e2e(
            Path::new("target/debug/boon_native_playground"),
            "todomvc",
            &native_gpu_title_token("ipc-backpressure"),
            1_500,
            60_000,
            &supervisor_report,
            &live_state_report,
            None,
            Some("a"),
            None,
            true,
            false,
            false,
        )?;
        let launch_success = isolated_real_window_launch_proof
            .get("status")
            .and_then(serde_json::Value::as_str)
            == Some("pass");
        push_audit_check(
            &mut checks,
            &mut blockers,
            "native-gpu-ipc:isolated-launch-command",
            launch_success,
            format!(
                "status={:?}, desktop_pass={:?}",
                isolated_real_window_launch_proof
                    .get("status")
                    .and_then(serde_json::Value::as_str),
                isolated_real_window_launch_proof
                    .get("desktop_pass")
                    .and_then(serde_json::Value::as_bool)
            ),
            (!launch_success).then(|| {
                "isolated native IPC launch failed to produce supervisor proof".to_owned()
            }),
        );
    } else if false && build.success() && wayland {
        let launcher_available = command_available("cosmic-background-launch");
        push_audit_check(
            &mut checks,
            &mut blockers,
            "native-gpu-ipc:cosmic-background-launch-available",
            launcher_available,
            format!("cosmic-background-launch available={launcher_available}"),
            (!launcher_available).then(|| {
                "cosmic-background-launch is required for workspace-isolated native IPC proof"
                    .to_owned()
            }),
        );
        if launcher_available {
            let cwd = std::env::current_dir()?;
            let script = format!(
                "cd {} && ./target/debug/boon_native_playground --role desktop --example cells --probe --child-hold-ms 10000 --dev-hold-ms 5000 --role-report-timeout-ms 60000 --report {} >>/tmp/boon-native-gpu-ipc.log 2>&1",
                shell_quote(&cwd.display().to_string()),
                shell_quote(&supervisor_report.display().to_string())
            );
            let launch = Command::new("cosmic-background-launch")
                .args(["--workspace", "boon-circuit", "--", "bash", "-lc", &script])
                .status()?;
            push_audit_check(
                &mut checks,
                &mut blockers,
                "native-gpu-ipc:cosmic-launch-command",
                launch.success(),
                format!("cosmic-background-launch status={launch}"),
                (!launch.success()).then(|| "cosmic-background-launch failed".to_owned()),
            );
            if launch.success() {
                let report_ready =
                    wait_for_json_report(&supervisor_report, Duration::from_secs(80));
                push_audit_check(
                    &mut checks,
                    &mut blockers,
                    "native-gpu-ipc:supervisor-report-written",
                    report_ready,
                    format!("{} ready={report_ready}", supervisor_report.display()),
                    (!report_ready).then(|| {
                        format!(
                            "desktop supervisor did not write `{}`",
                            supervisor_report.display()
                        )
                    }),
                );
            }
        }
    }

    let mut ipc_probe = json!({});
    let mut extra = json!({
        "requested_workspace": "boon-circuit",
        "launcher_command": "isolated-weston-headless-with-weston-test-control",
        "supervisor_report": supervisor_report,
        "live_state_report": live_state_report,
        "isolated_real_window_launch_proof": isolated_real_window_launch_proof,
        "live_preview_dev_windows": false,
        "bounded_ipc": false,
        "preview_blocked_on_ipc_count": serde_json::Value::Null,
        "queue_depth_max": serde_json::Value::Null,
        "full_state_mirroring_observed": false
    });
    if supervisor_report.exists() {
        let supervisor = read_json(&supervisor_report)?;
        ipc_probe = supervisor
            .get("dev_ipc_probe")
            .cloned()
            .unwrap_or_else(|| json!({}));
        if let Some(preview_frame_ms) = supervisor
            .pointer("/preview_surface_proof/presented_frame_ms")
            .and_then(serde_json::Value::as_f64)
        {
            extra["preview_surface_presented_frame_ms"] = json!(preview_frame_ms);
        }
        for key in [
            "process_model",
            "preview_child_pid",
            "dev_child_pid",
            "preview_child_cmdline",
            "dev_child_cmdline",
            "preview_role_report",
            "dev_role_report",
            "preview_role_report_sha256",
            "dev_role_report_sha256",
            "preview_survives_dev_exit",
            "preview_receives_example_name",
            "display_server",
            "display_connection",
            "preview_role_report",
            "dev_role_report",
            "preview_role_report_sha256",
            "dev_role_report_sha256",
            "preview_surface_proof",
            "preview_runtime_summary",
            "preview_runtime_summary",
        ] {
            if let Some(value) = supervisor.get(key) {
                extra[key] = value.clone();
            }
        }
    }
    if let Some(object) = ipc_probe.as_object() {
        for (key, value) in object {
            extra[key] = value.clone();
        }
        extra["live_preview_dev_windows"] = json!(true);
    }

    let bounded_ipc = extra
        .get("bounded_ipc")
        .and_then(serde_json::Value::as_bool)
        == Some(true);
    let live_ipc = extra
        .get("live_preview_dev_ipc")
        .and_then(serde_json::Value::as_bool)
        == Some(true);
    let preview_blocked = extra
        .get("preview_blocked_on_ipc_count")
        .and_then(serde_json::Value::as_u64)
        .unwrap_or(u64::MAX);
    let queue_depth_max = extra
        .get("queue_depth_max")
        .and_then(serde_json::Value::as_u64)
        .unwrap_or(u64::MAX);
    let no_full_mirroring = extra
        .get("full_state_mirroring_observed")
        .and_then(serde_json::Value::as_bool)
        == Some(false);
    let preview_frame_budget =
        native_gpu_budget_f64("frame", "preview_frame_ms_p95").unwrap_or(16.7);
    let heartbeat_budget = native_gpu_budget_f64("ipc", "heartbeat_gap_ms_max").unwrap_or(250.0);
    let rss_budget = native_gpu_budget_u64("memory", "rss_mib_max").unwrap_or(1024);
    let dropped_debug_budget =
        native_gpu_budget_u64("ipc", "dropped_debug_update_count_max").unwrap_or(100_000);
    let debug_query_budget =
        native_gpu_budget_u64("ipc", "debug_query_bytes_p95").unwrap_or(262_144);
    let debug_subscription_budget =
        native_gpu_budget_u64("ipc", "debug_subscription_bytes_p95").unwrap_or(262_144);
    let preview_frame_p95 = summary_p95_f64(&extra["preview_frame_ms_p50_p95_max"]);
    let heartbeat_gap_max = numeric_value_as_f64(&extra["preview_heartbeat_gap_ms_max"]);
    let preview_rss_mib_max = extra
        .get("preview_rss_mib_max")
        .and_then(serde_json::Value::as_u64);
    let dropped_debug_count = extra
        .get("dropped_debug_update_count")
        .and_then(serde_json::Value::as_u64);
    let debug_query_p95 = summary_p95_u64(&extra["debug_query_bytes_p50_p95_max"]);
    let debug_subscription_p95 = summary_p95_u64(&extra["debug_subscription_bytes_p50_p95_max"]);

    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:live-preview-dev-ipc",
        live_ipc,
        format!("live_preview_dev_ipc={live_ipc}"),
        (!live_ipc).then(|| "missing live preview/dev IPC evidence".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:bounded-queue",
        bounded_ipc && queue_depth_max <= queue_capacity,
        format!(
            "bounded_ipc={bounded_ipc}, queue_depth_max={queue_depth_max}, budget={queue_capacity}"
        ),
        (!(bounded_ipc && queue_depth_max <= queue_capacity))
            .then(|| "bounded IPC queue proof is missing or over budget".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:preview-never-blocked",
        preview_blocked == 0,
        format!("preview_blocked_on_ipc_count={preview_blocked}"),
        (preview_blocked != 0).then(|| "preview blocked on IPC".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:no-full-state-mirroring",
        no_full_mirroring,
        format!("full_state_mirroring_observed={}", !no_full_mirroring),
        (!no_full_mirroring).then(|| "IPC observed full-state mirroring".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:preview-frame-budget",
        preview_frame_p95.is_some_and(|value| value <= preview_frame_budget),
        format!("preview_frame_p95={preview_frame_p95:?}, budget={preview_frame_budget}"),
        preview_frame_p95
            .is_none_or(|value| value > preview_frame_budget)
            .then(|| "IPC backpressure proof lacks preview frame p95 within budget".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:heartbeat-budget",
        heartbeat_gap_max.is_some_and(|value| value <= heartbeat_budget),
        format!("heartbeat_gap_max={heartbeat_gap_max:?}, budget={heartbeat_budget}"),
        heartbeat_gap_max
            .is_none_or(|value| value > heartbeat_budget)
            .then(|| "IPC heartbeat gap proof is missing or over budget".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:rss-budget",
        preview_rss_mib_max.is_some_and(|value| value <= rss_budget),
        format!("preview_rss_mib_max={preview_rss_mib_max:?}, budget={rss_budget}"),
        preview_rss_mib_max
            .is_none_or(|value| value > rss_budget)
            .then(|| "IPC memory/RSS proof is missing or over budget".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:debug-update-drop-budget",
        dropped_debug_count.is_some_and(|value| value <= dropped_debug_budget),
        format!(
            "dropped_debug_update_count={dropped_debug_count:?}, budget={dropped_debug_budget}"
        ),
        dropped_debug_count
            .is_none_or(|value| value > dropped_debug_budget)
            .then(|| "dropped debug update count is missing or over budget".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:debug-byte-budgets",
        debug_query_p95.is_some_and(|value| value <= debug_query_budget)
            && debug_subscription_p95.is_some_and(|value| value <= debug_subscription_budget),
        format!(
            "debug_query_p95={debug_query_p95:?}/{debug_query_budget}, debug_subscription_p95={debug_subscription_p95:?}/{debug_subscription_budget}"
        ),
        (!(debug_query_p95.is_some_and(|value| value <= debug_query_budget)
            && debug_subscription_p95.is_some_and(|value| value <= debug_subscription_budget)))
        .then(|| "debug query/subscription byte budgets are missing or exceeded".to_owned()),
    );
    let replace_code_ok = native_gpu_replace_code_evidence_ok(&extra, "");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-ipc:dev-replace-code-command",
        replace_code_ok,
        format!(
            "dev_sent_replace_code={:?}, preview_command={:?}, hash_matches={:?}",
            extra
                .get("dev_sent_replace_code")
                .and_then(serde_json::Value::as_bool),
            extra
                .pointer("/replace_code/preview_command")
                .and_then(serde_json::Value::as_str),
            extra
                .pointer("/replace_code/hash_matches")
                .and_then(serde_json::Value::as_bool)
        ),
        (!replace_code_ok)
            .then(|| "IPC proof lacks bounded dev-to-preview ReplaceCode evidence".to_owned()),
    );

    write_native_gate_report(
        args,
        "verify-native-gpu-ipc-backpressure",
        checks,
        blockers,
        extra,
    )
}

fn verify_native_gpu_observability(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    let mut checks = Vec::new();
    let mut blockers = Vec::new();
    let supervisor_report =
        PathBuf::from("target/reports/native-gpu/.observability-supervisor.json");
    let live_state_report =
        PathBuf::from("target/artifacts/native-gpu/observability-live-state.json");
    let _ = std::fs::remove_file(&supervisor_report);
    let _ = std::fs::remove_file(&live_state_report);
    let wayland = std::env::var_os("WAYLAND_DISPLAY").is_some()
        && std::env::var("XDG_SESSION_TYPE").unwrap_or_default() == "wayland";
    let isolated_real_window_available = command_available("weston")
        && command_available("wayland-info")
        && weston_test_plugin_path().is_some()
        && weston_test_driver_path().is_some();
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-observability:isolated-real-window-environment",
        isolated_real_window_available,
        format!(
            "WAYLAND_DISPLAY={:?}, XDG_SESSION_TYPE={:?}, isolated_real_window_available={isolated_real_window_available}",
            std::env::var("WAYLAND_DISPLAY").ok(),
            std::env::var("XDG_SESSION_TYPE").ok()
        ),
        (!isolated_real_window_available).then(|| {
            "native observability proof requires the isolated Weston real-window harness".to_owned()
        }),
    );

    let build = Command::new("cargo")
        .args(["build", "-p", "boon_native_playground"])
        .status()?;
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-observability:playground-build",
        build.success(),
        format!("cargo build -p boon_native_playground status={build}"),
        (!build.success()).then(|| "failed to build boon_native_playground".to_owned()),
    );

    let mut isolated_real_window_launch_proof = json!({"status": "not-run"});
    if build.success() && isolated_real_window_available {
        isolated_real_window_launch_proof = run_isolated_weston_desktop_preview_e2e(
            Path::new("target/debug/boon_native_playground"),
            "todomvc",
            &native_gpu_title_token("observability"),
            1_500,
            60_000,
            &supervisor_report,
            &live_state_report,
            None,
            Some("a"),
            None,
            true,
            false,
            false,
        )?;
        let launch_success = isolated_real_window_launch_proof
            .get("status")
            .and_then(serde_json::Value::as_str)
            == Some("pass");
        push_audit_check(
            &mut checks,
            &mut blockers,
            "native-gpu-observability:isolated-launch-command",
            launch_success,
            format!(
                "status={:?}, desktop_pass={:?}",
                isolated_real_window_launch_proof
                    .get("status")
                    .and_then(serde_json::Value::as_str),
                isolated_real_window_launch_proof
                    .get("desktop_pass")
                    .and_then(serde_json::Value::as_bool)
            ),
            (!launch_success).then(|| {
                "isolated native observability launch failed to produce supervisor proof".to_owned()
            }),
        );
    } else if false && build.success() && wayland {
        let launcher_available = command_available("cosmic-background-launch");
        push_audit_check(
            &mut checks,
            &mut blockers,
            "native-gpu-observability:cosmic-background-launch-available",
            launcher_available,
            format!("cosmic-background-launch available={launcher_available}"),
            (!launcher_available).then(|| {
                "cosmic-background-launch is required for workspace-isolated observability proof"
                    .to_owned()
            }),
        );
        if launcher_available {
            let cwd = std::env::current_dir()?;
            let script = format!(
                "cd {} && ./target/debug/boon_native_playground --role desktop --example cells --probe --child-hold-ms 10000 --dev-hold-ms 5000 --role-report-timeout-ms 60000 --report {} >>/tmp/boon-native-gpu-observability.log 2>&1",
                shell_quote(&cwd.display().to_string()),
                shell_quote(&supervisor_report.display().to_string())
            );
            let launch = Command::new("cosmic-background-launch")
                .args(["--workspace", "boon-circuit", "--", "bash", "-lc", &script])
                .status()?;
            push_audit_check(
                &mut checks,
                &mut blockers,
                "native-gpu-observability:cosmic-launch-command",
                launch.success(),
                format!("cosmic-background-launch status={launch}"),
                (!launch.success()).then(|| "cosmic-background-launch failed".to_owned()),
            );
            if launch.success() {
                let report_ready =
                    wait_for_json_report(&supervisor_report, Duration::from_secs(80));
                push_audit_check(
                    &mut checks,
                    &mut blockers,
                    "native-gpu-observability:supervisor-report-written",
                    report_ready,
                    format!("{} ready={report_ready}", supervisor_report.display()),
                    (!report_ready).then(|| {
                        format!(
                            "desktop supervisor did not write `{}`",
                            supervisor_report.display()
                        )
                    }),
                );
            }
        }
    }

    let mut ipc_probe = json!({});
    let mut extra = json!({
        "requested_workspace": "boon-circuit",
        "launcher_command": "isolated-weston-headless-with-weston-test-control",
        "supervisor_report": supervisor_report,
        "live_state_report": live_state_report,
        "isolated_real_window_launch_proof": isolated_real_window_launch_proof,
        "bounded_observability": false,
        "full_state_mirroring_observed": false,
        "live_preview_dev_windows": false,
        "observability_scope": "live-bounded-query-and-subscription-ipc",
        "native_counter_inventory_version": 1,
        "native_renderer_counter_inventory": native_renderer_counter_inventory(),
        "native_stage_counter_availability": native_stage_counter_availability(),
        "runtime_summary_fields": ["node_count", "dirty_count", "frame_epoch", "source_epoch"],
        "allowed_query_shapes": ["value-slice", "dependency-neighborhood", "document-slice"],
        "forbidden_payloads": ["full-runtime-state", "full-document-tree", "full-display-list", "gpu-instance-stream"]
    });
    if supervisor_report.exists() {
        let supervisor = read_json(&supervisor_report)?;
        ipc_probe = supervisor
            .get("dev_ipc_probe")
            .cloned()
            .unwrap_or_else(|| json!({}));
        if let Some(preview_frame_ms) = supervisor
            .pointer("/preview_surface_proof/presented_frame_ms")
            .and_then(serde_json::Value::as_f64)
        {
            extra["preview_surface_presented_frame_ms"] = json!(preview_frame_ms);
        }
        for key in [
            "process_model",
            "preview_child_pid",
            "dev_child_pid",
            "preview_child_cmdline",
            "dev_child_cmdline",
            "preview_role_report",
            "dev_role_report",
            "preview_role_report_sha256",
            "dev_role_report_sha256",
            "preview_survives_dev_exit",
            "preview_receives_example_name",
            "display_server",
            "display_connection",
            "preview_role_report",
            "dev_role_report",
            "preview_role_report_sha256",
            "dev_role_report_sha256",
            "preview_surface_proof",
        ] {
            if let Some(value) = supervisor.get(key) {
                extra[key] = value.clone();
            }
        }
    }
    if let Some(object) = ipc_probe.as_object() {
        for key in [
            "ipc_queue_depth_p50_p95_max",
            "ipc_queue_depth_sample_count",
            "telemetry_serialize_ms_p50_p95_max",
            "telemetry_serialize_sample_count",
            "debug_query_bytes_p50_p95_max",
            "debug_query_byte_sample_count",
            "debug_subscription_bytes_p50_p95_max",
            "debug_subscription_byte_sample_count",
            "dev_command_apply_ms_p50_p95_max",
            "dev_command_apply_sample_count",
            "dev_request_round_trip_ms_p50_p95_max",
            "dev_request_round_trip_sample_count",
            "transport",
            "live_preview_dev_ipc",
            "dev_connected_to_preview",
            "message_count",
            "preview_blocked_on_ipc_count",
            "preview_blocked_on_ipc_duration_ms_total",
            "preview_blocked_on_ipc_duration_ms_max",
            "preview_ipc_request_count",
            "preview_ipc_request_bytes",
            "preview_ipc_response_bytes",
            "preview_ipc_request_round_trip_ms_p50_p95_max",
            "preview_ipc_request_round_trip_sample_count",
            "preview_ipc_response_write_ms_p50_p95_max",
            "preview_ipc_response_write_sample_count",
            "preview_frame_ms_p50_p95_max",
            "preview_frame_sample_count",
            "preview_heartbeat_gap_ms_max",
            "preview_heartbeat_gap_sample_count",
            "preview_rss_mib_max",
            "dropped_telemetry_count",
            "dropped_frame_metrics_count",
            "dropped_debug_update_count",
            "ipc_counter_sources",
            "observability_stress_profile",
            "dev_sent_replace_code",
            "replace_code",
            "runtime_summary_query",
            "latest_wins_input_count",
            "latest_wins_coalesced_count",
            "latest_wins_dropped_count",
            "latest_wins_completed_command_id",
            "latest_wins_completed_revision",
            "stale_revision_discard_count",
            "semantic_coalescing_reason",
            "latest_wins_worker",
        ] {
            if let Some(value) = object.get(key) {
                extra[key] = value.clone();
            }
        }
        extra["bounded_observability"] = json!(true);
        extra["live_preview_dev_windows"] = json!(true);
        if let Some(value) = object.get("full_state_mirroring_observed") {
            extra["full_state_mirroring_observed"] = value.clone();
        }
    }
    extra["native_ipc_counter_inventory_version"] = json!(1);
    extra["native_ipc_stage_counters"] = native_ipc_stage_counters(&extra);
    extra["native_ipc_counter_availability"] = native_ipc_counter_availability(&extra);

    let live_ipc = extra
        .get("live_preview_dev_ipc")
        .and_then(serde_json::Value::as_bool)
        == Some(true);
    let bounded_observability = extra
        .get("bounded_observability")
        .and_then(serde_json::Value::as_bool)
        == Some(true);
    let no_full_mirroring = extra
        .get("full_state_mirroring_observed")
        .and_then(serde_json::Value::as_bool)
        == Some(false);
    let has_query_budget = extra
        .get("debug_query_bytes_p50_p95_max")
        .and_then(serde_json::Value::as_object)
        .is_some_and(|summary| {
            summary
                .get("max")
                .and_then(serde_json::Value::as_u64)
                .is_some()
        });
    let has_subscription_budget = extra
        .get("debug_subscription_bytes_p50_p95_max")
        .and_then(serde_json::Value::as_object)
        .is_some_and(|summary| {
            summary
                .get("max")
                .and_then(serde_json::Value::as_u64)
                .is_some()
        });
    let preview_frame_budget =
        native_gpu_budget_f64("frame", "preview_frame_ms_p95").unwrap_or(16.7);
    let heartbeat_budget = native_gpu_budget_f64("ipc", "heartbeat_gap_ms_max").unwrap_or(250.0);
    let dropped_debug_budget =
        native_gpu_budget_u64("ipc", "dropped_debug_update_count_max").unwrap_or(100_000);
    let debug_query_budget =
        native_gpu_budget_u64("ipc", "debug_query_bytes_p95").unwrap_or(262_144);
    let debug_subscription_budget =
        native_gpu_budget_u64("ipc", "debug_subscription_bytes_p95").unwrap_or(262_144);
    let preview_frame_p95 = summary_p95_f64(&extra["preview_frame_ms_p50_p95_max"]);
    let heartbeat_gap_max = numeric_value_as_f64(&extra["preview_heartbeat_gap_ms_max"]);
    let dropped_debug_count = extra
        .get("dropped_debug_update_count")
        .and_then(serde_json::Value::as_u64);
    let debug_query_p95 = summary_p95_u64(&extra["debug_query_bytes_p50_p95_max"]);
    let debug_subscription_p95 = summary_p95_u64(&extra["debug_subscription_bytes_p50_p95_max"]);
    let stress_profile = &extra["observability_stress_profile"];
    let stress_profile_pass = stress_profile
        .get("runtime_value_graph_enabled")
        .and_then(serde_json::Value::as_bool)
        == Some(true)
        && stress_profile
            .get("busy_dev_graph_view_enabled")
            .and_then(serde_json::Value::as_bool)
            == Some(true)
        && stress_profile
            .get("debug_updates_coalesced")
            .and_then(serde_json::Value::as_bool)
            == Some(true)
        && stress_profile
            .get("debug_queries_paged")
            .and_then(serde_json::Value::as_bool)
            == Some(true);

    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-observability:bounded-subscriptions",
        bounded_observability && has_subscription_budget,
        format!(
            "bounded_observability={bounded_observability}, has_subscription_budget={has_subscription_budget}"
        ),
        (!(bounded_observability && has_subscription_budget))
            .then(|| "bounded subscription telemetry evidence is missing".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-observability:no-full-state-mirroring",
        no_full_mirroring,
        format!("full_state_mirroring_observed={}", !no_full_mirroring),
        (!no_full_mirroring).then(|| "observability mirrored full state".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-observability:live-transport-integration",
        live_ipc && has_query_budget,
        format!("live_preview_dev_ipc={live_ipc}, has_query_budget={has_query_budget}"),
        (!(live_ipc && has_query_budget))
            .then(|| "bounded observability transport is not live preview/dev evidence".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-observability:overload-profile",
        stress_profile_pass,
        format!("observability_stress_profile={stress_profile}"),
        (!stress_profile_pass).then(|| {
            "observability overload profile is missing bounded graph/query evidence".to_owned()
        }),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-observability:preview-frame-budget",
        preview_frame_p95.is_some_and(|value| value <= preview_frame_budget),
        format!("preview_frame_p95={preview_frame_p95:?}, budget={preview_frame_budget}"),
        preview_frame_p95
            .is_none_or(|value| value > preview_frame_budget)
            .then(|| "observability overload lacks preview frame p95 within budget".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-observability:heartbeat-and-drop-budgets",
        heartbeat_gap_max.is_some_and(|value| value <= heartbeat_budget)
            && dropped_debug_count.is_some_and(|value| value <= dropped_debug_budget),
        format!(
            "heartbeat_gap_max={heartbeat_gap_max:?}/{heartbeat_budget}, dropped_debug_update_count={dropped_debug_count:?}/{dropped_debug_budget}"
        ),
        (!(heartbeat_gap_max.is_some_and(|value| value <= heartbeat_budget)
            && dropped_debug_count.is_some_and(|value| value <= dropped_debug_budget)))
        .then(|| "observability heartbeat/drop budgets are missing or exceeded".to_owned()),
    );
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-observability:debug-byte-budgets",
        debug_query_p95.is_some_and(|value| value <= debug_query_budget)
            && debug_subscription_p95.is_some_and(|value| value <= debug_subscription_budget),
        format!(
            "debug_query_p95={debug_query_p95:?}/{debug_query_budget}, debug_subscription_p95={debug_subscription_p95:?}/{debug_subscription_budget}"
        ),
        (!(debug_query_p95.is_some_and(|value| value <= debug_query_budget)
            && debug_subscription_p95.is_some_and(|value| value <= debug_subscription_budget)))
        .then(|| {
            "observability debug query/subscription byte budgets are missing or exceeded".to_owned()
        }),
    );
    let replace_code_ok = native_gpu_replace_code_evidence_ok(&extra, "");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "native-gpu-observability:dev-replace-code-command",
        replace_code_ok,
        format!(
            "dev_sent_replace_code={:?}, preview_command={:?}, hash_matches={:?}",
            extra
                .get("dev_sent_replace_code")
                .and_then(serde_json::Value::as_bool),
            extra
                .pointer("/replace_code/preview_command")
                .and_then(serde_json::Value::as_str),
            extra
                .pointer("/replace_code/hash_matches")
                .and_then(serde_json::Value::as_bool)
        ),
        (!replace_code_ok).then(|| {
            "observability proof lacks bounded dev-to-preview ReplaceCode evidence".to_owned()
        }),
    );

    write_native_gate_report(
        args,
        "verify-native-gpu-observability",
        checks,
        blockers,
        extra,
    )
}

