fn verify_bytes_machine_plan_all(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    verify_bytes_machine_plan_all_with_required(args, bytes_machine_plan_required_reports())
}

fn verify_bytes_machine_plan_all_with_required(
    args: &[String],
    required: &[BytesMachinePlanRequiredReport],
) -> Result<(), Box<dyn std::error::Error>> {
    const COMMAND: &str = "verify-bytes-machine-plan-all";
    let report = report_arg(args)
        .unwrap_or_else(|| PathBuf::from("target/reports/bytes-plan/bytes-machine-plan-all.json"));
    let mut checks = Vec::new();
    let mut blockers = Vec::new();
    let check_existing = args.iter().any(|arg| arg == "--check-existing");
    push_audit_check(
        &mut checks,
        &mut blockers,
        "requires-check-existing",
        check_existing,
        "aggregate BYTES/MachinePlan gate only validates already generated child evidence",
        Some("missing --check-existing".to_owned()),
    );

    let current_commit = git_commit();
    let mut child_reports = Vec::new();
    let mut aggregate_artifacts = Vec::new();
    let mut proof_report_count = 0usize;
    let mut diagnostic_report_count = 0usize;
    let mut plan_executor_report_count = 0usize;
    let mut no_fallback_plan_executor_count = 0usize;

    if check_existing {
        for required_report in required {
            let path = Path::new(required_report.path);
            let exists = path.exists();
            push_audit_check(
                &mut checks,
                &mut blockers,
                format!("{}:present", required_report.label),
                exists,
                required_report.path,
                Some(format!(
                    "missing required report `{}`",
                    required_report.path
                )),
            );
            if !exists {
                continue;
            }

            match artifact_hash(path) {
                Ok(artifact) => aggregate_artifacts.push(artifact),
                Err(error) => push_audit_check(
                    &mut checks,
                    &mut blockers,
                    format!("{}:aggregate-artifact-hash", required_report.label),
                    false,
                    error.to_string(),
                    Some(format!(
                        "failed to hash required report `{}`: {error}",
                        required_report.path
                    )),
                ),
            }

            let schema_result = verify_report_schema(path);
            push_audit_check(
                &mut checks,
                &mut blockers,
                format!("{}:schema-valid", required_report.label),
                schema_result.is_ok(),
                schema_result
                    .as_ref()
                    .err()
                    .map(std::string::ToString::to_string)
                    .unwrap_or_else(|| "report schema accepted child report".to_owned()),
                Some(format!(
                    "required report `{}` failed report schema",
                    required_report.path
                )),
            );

            let child = match read_json(path) {
                Ok(child) => child,
                Err(error) => {
                    push_audit_check(
                        &mut checks,
                        &mut blockers,
                        format!("{}:json-readable", required_report.label),
                        false,
                        error.to_string(),
                        Some(format!(
                            "required report `{}` is not readable JSON: {error}",
                            required_report.path
                        )),
                    );
                    continue;
                }
            };
            let status = child.get("status").and_then(serde_json::Value::as_str);
            let command = child.get("command").and_then(serde_json::Value::as_str);
            let mode = child
                .get("measurement_mode")
                .and_then(serde_json::Value::as_str);
            let git = child.get("git_commit").and_then(serde_json::Value::as_str);
            let child_status_pass = status == Some("pass");
            let command_matches = command == Some(required_report.command);
            let mode_matches = mode == Some(required_report.measurement_mode);
            let git_matches = if required_report.command == "bytes-plan-phase0-baseline" {
                git.is_some()
            } else {
                git.map(|git| {
                    git == current_commit
                        || git.starts_with(&current_commit)
                        || current_commit.starts_with(git)
                })
                .unwrap_or(false)
            };
            let (artifact_hashes_fresh, artifact_detail) = child_artifact_hashes_fresh(&child)
                .unwrap_or_else(|error| {
                    (
                        false,
                        format!("could not verify child artifact hashes: {error}"),
                    )
                });
            push_audit_check(
                &mut checks,
                &mut blockers,
                format!("{}:status-pass", required_report.label),
                child_status_pass,
                format!("status={status:?}"),
                Some(format!(
                    "required report `{}` did not pass",
                    required_report.path
                )),
            );
            push_audit_check(
                &mut checks,
                &mut blockers,
                format!("{}:command-match", required_report.label),
                command_matches,
                format!(
                    "expected command `{}`, got {command:?}",
                    required_report.command
                ),
                Some(format!(
                    "required report `{}` command mismatch",
                    required_report.path
                )),
            );
            push_audit_check(
                &mut checks,
                &mut blockers,
                format!("{}:measurement-mode-match", required_report.label),
                mode_matches,
                format!(
                    "expected measurement_mode `{}`, got {mode:?}",
                    required_report.measurement_mode
                ),
                Some(format!(
                    "required report `{}` measurement mode mismatch",
                    required_report.path
                )),
            );
            push_audit_check(
                &mut checks,
                &mut blockers,
                format!("{}:git-current", required_report.label),
                git_matches,
                format!("report git={git:?}, current git={current_commit}"),
                Some(format!(
                    "required report `{}` was not generated for current commit",
                    required_report.path
                )),
            );
            push_audit_check(
                &mut checks,
                &mut blockers,
                format!("{}:artifact-hashes-fresh", required_report.label),
                artifact_hashes_fresh,
                artifact_detail,
                Some(format!(
                    "required report `{}` has stale artifact hashes",
                    required_report.path
                )),
            );

            if required_report.measurement_mode == "proof" {
                proof_report_count += 1;
            } else {
                diagnostic_report_count += 1;
            }
            if let Some((pass, detail)) = plan_executor_no_fallback_counts_zero(&child) {
                plan_executor_report_count += 1;
                if pass {
                    no_fallback_plan_executor_count += 1;
                }
                push_audit_check(
                    &mut checks,
                    &mut blockers,
                    format!(
                        "{}:plan-executor-no-fallback-counters",
                        required_report.label
                    ),
                    pass,
                    detail,
                    Some(format!(
                        "required plan-executor report `{}` used fallback execution",
                        required_report.path
                    )),
                );
            }
            let child_sha256 = cached_sha256_file(path)?;
            let expression_kinds = child_expression_kinds(&child);
            let source_payload_typing = child_source_payload_typing_summary(&child);
            let command_argv = child
                .get("command_argv")
                .cloned()
                .unwrap_or_else(|| json!([]));
            let mut child_report = json!({
                "label": required_report.label,
                "path": required_report.path,
                "sha256": child_sha256,
                "status": status.unwrap_or("missing"),
                "command": command.unwrap_or("missing"),
                "command_argv": command_argv,
                "measurement_mode": mode.unwrap_or("missing"),
                "git_commit": git.unwrap_or("missing"),
                "schema_valid": schema_result.is_ok(),
                "artifact_hashes_fresh": artifact_hashes_fresh,
                "expression_kinds": expression_kinds,
            });
            if let Some(source_payload_typing) = source_payload_typing
                && let Some(object) = child_report.as_object_mut()
            {
                object.insert("source_payload_typing".to_owned(), source_payload_typing);
            }
            child_reports.push(child_report);
        }
    }

    let aggregate_checks_pass = blockers.is_empty();
    let extra = json!({
        "aggregate_scope": "bytes-machine-plan-current-slices",
        "check_existing": check_existing,
        "required_report_count": required.len(),
        "checked_report_count": child_reports.len(),
        "proof_report_count": proof_report_count,
        "diagnostic_report_count": diagnostic_report_count,
        "plan_executor_report_count": plan_executor_report_count,
        "no_fallback_plan_executor_count": no_fallback_plan_executor_count,
        "aggregate_checks_pass": aggregate_checks_pass,
        "child_reports": child_reports,
        "artifact_sha256s": aggregate_artifacts
    });
    write_static_gate_report(args, COMMAND, report, checks, blockers, extra)
}

fn child_expression_kinds(report: &serde_json::Value) -> Vec<String> {
    let mut kinds = BTreeSet::new();
    collect_child_expression_kinds(report, &mut kinds);
    kinds.into_iter().collect()
}

fn collect_child_expression_kinds(value: &serde_json::Value, kinds: &mut BTreeSet<String>) {
    match value {
        serde_json::Value::Object(object) => {
            if let Some(kind) = object
                .get("expression_kind")
                .and_then(serde_json::Value::as_str)
            {
                kinds.insert(kind.to_owned());
            }
            if let Some(kind) = object.get("kind").and_then(serde_json::Value::as_str)
                && (kind.starts_with("bytes_") || kind == "text_to_bytes")
            {
                kinds.insert(kind.to_owned());
            }
            for child in object.values() {
                collect_child_expression_kinds(child, kinds);
            }
        }
        serde_json::Value::Array(items) => {
            for child in items {
                collect_child_expression_kinds(child, kinds);
            }
        }
        _ => {}
    }
}

fn child_source_payload_typing_summary(report: &serde_json::Value) -> Option<serde_json::Value> {
    let mut route_fields = Vec::new();
    let mut update_fields = Vec::new();
    let mut operand_fields = Vec::new();
    let mut typed_fields = Vec::new();
    collect_child_source_payload_typing(
        report,
        &mut route_fields,
        &mut update_fields,
        &mut operand_fields,
        &mut typed_fields,
    );
    route_fields.sort();
    route_fields.dedup();
    update_fields.sort();
    update_fields.dedup();
    operand_fields.sort();
    operand_fields.dedup();
    typed_fields.sort();
    typed_fields.dedup();
    let route_count = route_fields.len();
    let update_count = update_fields.len();
    let operand_count = operand_fields.len();
    let typed_descriptor_count = typed_fields.len();
    if route_count == 0 && update_count == 0 && operand_count == 0 && typed_descriptor_count == 0 {
        return None;
    }
    let typed_field_entries = typed_fields
        .iter()
        .map(|(field, value_type)| json!({ "field": field, "value_type": value_type }))
        .collect::<Vec<_>>();
    Some(json!({
        "source_payload_route_count": route_count,
        "bytes_payload_route_count": route_fields.iter().filter(|field| field.as_str() == "Bytes").count(),
        "source_payload_update_count": update_count,
        "bytes_source_payload_update_count": update_fields.iter().filter(|field| field.as_str() == "Bytes").count(),
        "typed_source_payload_operand_count": operand_count,
        "typed_payload_descriptor_count": typed_descriptor_count,
        "bytes_typed_payload_descriptor_count": typed_fields.iter().filter(|(field, value_type)| field == "Bytes" && value_type == "bytes").count(),
        "fields": route_fields,
        "update_fields": update_fields,
        "operand_fields": operand_fields,
        "typed_fields": typed_field_entries,
        "typed_payload_summary_complete": route_count > 0 && update_count > 0 && operand_count > 0 && typed_descriptor_count > 0,
    }))
}

fn collect_child_source_payload_typing(
    value: &serde_json::Value,
    route_fields: &mut Vec<String>,
    update_fields: &mut Vec<String>,
    operand_fields: &mut Vec<String>,
    typed_fields: &mut Vec<(String, String)>,
) {
    match value {
        serde_json::Value::Object(object) => {
            if let Some(fields) = object
                .get("payload_schema")
                .and_then(|schema| schema.get("fields"))
                .and_then(serde_json::Value::as_array)
            {
                for field in fields {
                    if let Some(field) = field.as_str() {
                        route_fields.push(field.to_owned());
                    }
                }
            }
            if let Some(descriptors) = object
                .get("typed_fields")
                .and_then(serde_json::Value::as_array)
            {
                for descriptor in descriptors {
                    if let (Some(field), Some(value_type)) = (
                        descriptor.get("field").and_then(source_payload_field_label),
                        descriptor
                            .get("value_type")
                            .and_then(serde_json::Value::as_str),
                    ) {
                        typed_fields.push((field.to_owned(), value_type.to_owned()));
                    }
                }
            }
            if let Some(field) = object
                .get("source_payload_field")
                .and_then(serde_json::Value::as_str)
            {
                update_fields.push(field.to_owned());
            }
            if object.get("kind").and_then(serde_json::Value::as_str) == Some("source_payload")
                && let Some(field) = object
                    .get("id")
                    .and_then(|id| id.get("field"))
                    .and_then(serde_json::Value::as_str)
            {
                operand_fields.push(field.to_owned());
            }
            for child in object.values() {
                collect_child_source_payload_typing(
                    child,
                    route_fields,
                    update_fields,
                    operand_fields,
                    typed_fields,
                );
            }
        }
        serde_json::Value::Array(items) => {
            for child in items {
                collect_child_source_payload_typing(
                    child,
                    route_fields,
                    update_fields,
                    operand_fields,
                    typed_fields,
                );
            }
        }
        _ => {}
    }
}

fn source_payload_field_label(value: &serde_json::Value) -> Option<&str> {
    value.as_str().or_else(|| {
        value
            .as_object()
            .and_then(|object| object.keys().next().map(String::as_str))
    })
}

fn child_artifact_hashes_fresh(
    report: &serde_json::Value,
) -> Result<(bool, String), Box<dyn std::error::Error>> {
    let artifacts = report
        .get("artifact_sha256s")
        .and_then(serde_json::Value::as_array)
        .ok_or("report missing artifact_sha256s array")?;
    let mut stale = Vec::new();
    for artifact in artifacts {
        let path = artifact
            .get("path")
            .and_then(serde_json::Value::as_str)
            .ok_or("artifact missing path")?;
        let expected = artifact
            .get("sha256")
            .and_then(serde_json::Value::as_str)
            .ok_or("artifact missing sha256")?;
        let actual = cached_sha256_file(Path::new(path))?;
        if actual != expected {
            stale.push(format!("{path}: expected {expected}, got {actual}"));
        }
    }
    if stale.is_empty() {
        Ok((
            true,
            format!("{} child artifact hash(es) are fresh", artifacts.len()),
        ))
    } else {
        Ok((false, stale.join("; ")))
    }
}

fn bytes_machine_plan_child_rejection_reasons(
    required_report: &BytesMachinePlanRequiredReport,
) -> Vec<String> {
    let mut reasons = Vec::new();
    let path = Path::new(required_report.path);
    if !path.exists() {
        reasons.push(format!(
            "missing required report `{}`",
            required_report.path
        ));
        return reasons;
    }

    if let Err(error) = verify_report_schema(path) {
        reasons.push(format!(
            "required report `{}` failed report schema: {error}",
            required_report.path
        ));
    }

    let child = match read_json(path) {
        Ok(child) => child,
        Err(error) => {
            reasons.push(format!(
                "required report `{}` is not readable JSON: {error}",
                required_report.path
            ));
            return reasons;
        }
    };

    let status = child.get("status").and_then(serde_json::Value::as_str);
    if status != Some("pass") {
        reasons.push(format!(
            "required report `{}` did not pass: status={status:?}",
            required_report.path
        ));
    }

    let command = child.get("command").and_then(serde_json::Value::as_str);
    if command != Some(required_report.command) {
        reasons.push(format!(
            "required report `{}` command mismatch: expected `{}`, got {command:?}",
            required_report.path, required_report.command
        ));
    }

    let mode = child
        .get("measurement_mode")
        .and_then(serde_json::Value::as_str);
    if mode != Some(required_report.measurement_mode) {
        reasons.push(format!(
            "required report `{}` measurement mode mismatch: expected `{}`, got {mode:?}",
            required_report.path, required_report.measurement_mode
        ));
    }

    let current_commit = git_commit();
    let git = child.get("git_commit").and_then(serde_json::Value::as_str);
    let git_matches = if required_report.command == "bytes-plan-phase0-baseline" {
        git.is_some()
    } else {
        git.map(|git| {
            git == current_commit
                || git.starts_with(&current_commit)
                || current_commit.starts_with(git)
        })
        .unwrap_or(false)
    };
    if !git_matches {
        reasons.push(format!(
            "required report `{}` was not generated for current commit: report git={git:?}, current git={current_commit}",
            required_report.path
        ));
    }

    match child_artifact_hashes_fresh(&child) {
        Ok((true, _)) => {}
        Ok((false, detail)) => reasons.push(format!(
            "required report `{}` has stale artifact hashes: {detail}",
            required_report.path
        )),
        Err(error) => reasons.push(format!(
            "could not verify child artifact hashes for `{}`: {error}",
            required_report.path
        )),
    }

    if let Some((false, detail)) = plan_executor_no_fallback_counts_zero(&child) {
        reasons.push(format!(
            "required plan-executor report `{}` used fallback execution: {detail}",
            required_report.path
        ));
    }

    reasons
}

fn plan_executor_no_fallback_counts_zero(report: &serde_json::Value) -> Option<(bool, String)> {
    let executor = report.get("plan_executor")?;
    let mut failures = Vec::new();
    let mut details = Vec::new();
    for key in [
        "runtime_ast_eval_count",
        "executable_string_path_count",
        "unknown_plan_op_count",
        "graph_rebuild_count",
        "graph_clones_per_item",
    ] {
        let value = executor.get(key).and_then(serde_json::Value::as_u64);
        details.push(format!("{key}={value:?}"));
        if value != Some(0) {
            failures.push(key);
        }
    }
    Some((failures.is_empty(), details.join(", ")))
}

fn verify_negative(args: &[String]) -> Result<(), Box<dyn std::error::Error>> {
    verify_negative_name(named_arg(args, 1)?)
}

