    #[test]
    fn isolated_scroll_input_evidence_overrides_planned_operator_wheel_input() {
        let frame_key = json!({
            "frame_seq": 84,
            "content_revision": 25,
            "layout_revision": 5,
            "render_scene_revision": 21,
            "surface_id": "preview:test",
            "surface_epoch": 1,
            "input_event_seq": 12,
            "present_id": 84,
            "proof_request_id": null
        });
        let isolated = json!({
            "status": "fail",
            "method": "isolated-weston-headless-with-weston-test-control",
            "driver_pass": true,
            "desktop_pass": false,
            "real_os_events_observed": true,
            "driver_effect_observed": true,
            "measured_loop_pass": true,
            "preview_input_adapter": {
                "installed": true,
                "real_os_events_observed": true,
                "synthetic_input_probe": false,
                "mouse_scroll_event_count": 4,
                "scroll_delta_x": 360.0,
                "scroll_delta_y": 480.0,
                "mouse_last_window_protocol_id": 9,
                "wheel_api": "app_window_mouse_wheel",
                "per_window_event_provenance_api": "app_window_protocol_surface"
            },
            "measured_loop_report": {
                "status": "pass",
                "frame_evidence_key": frame_key.clone(),
                "surface_id": "preview:test",
                "surface_epoch": 1,
                "rendered_frame_count": 84,
                "presented_revision": 25,
                "last_render_content_revision": 25,
                "last_render_layout_revision": 5,
                "last_render_scene_revision": 21,
                "last_external_render_proof": {
                    "status": "pass",
                    "render_backend_trait": "boon_native_gpu::encode_render_scene_to_surface",
                    "offscreen_app_owned_scene_readback_skipped": true
                },
                "last_interactive_readback_artifact": {
                    "capture_method": "wgpu-visible-surface-copy-src-readback",
                    "readback_poll_status": "completed_before_deadline",
                    "nonblank_samples": 16,
                    "frame_evidence_key": frame_key.clone()
                }
            }
        });
        let mut report = json!({
            "preview_frame_ms_p95": 4.0,
            "operator_host_wheel_input": true,
            "operator_host_input_evidence": {
                "host_events": [{"kind": "wheel"}, {"kind": "wheel"}],
                "deltas": {"vertical_px": 720.0, "horizontal_px": 480.0}
            },
            "preview_surface_proof": {
                "adapter_is_software": false
            }
        });

        promote_isolated_scroll_measured_loop_evidence(
            &mut report,
            &isolated,
            "preview_surface_proof",
        );
        add_native_scroll_model_evidence(&mut report, "generic", false);

        assert_eq!(
            report
                .get("isolated_scroll_measured_loop_evidence_promoted")
                .and_then(serde_json::Value::as_bool),
            Some(true)
        );
        assert_eq!(
            report
                .get("wheel_input_evidence_source")
                .and_then(serde_json::Value::as_str),
            Some("real-window-native-input-adapter")
        );
        assert_eq!(
            report
                .get("selected_wheel_input_observed")
                .and_then(serde_json::Value::as_bool),
            Some(true)
        );
        assert_eq!(
            report
                .get("native_wheel_adapter_installed")
                .and_then(serde_json::Value::as_bool),
            Some(true)
        );
        assert_eq!(
            report
                .pointer("/preview_surface_proof/external_render_proof/status")
                .and_then(serde_json::Value::as_str),
            Some("pass")
        );
        assert_eq!(report.pointer("/frame_evidence_key"), Some(&frame_key));
        assert_eq!(
            report
                .get("real_window_timing_proven")
                .and_then(serde_json::Value::as_bool),
            Some(false)
        );
        assert_eq!(
            report
                .get("required_real_window_speed_proven")
                .and_then(serde_json::Value::as_bool),
            Some(false)
        );
        assert_eq!(
            report
                .get("budget_pass")
                .and_then(serde_json::Value::as_bool),
            Some(false)
        );
    }

    #[test]
    fn axis_surface_report_fallback_keeps_loop_readback_and_role_timing_strict() {
        let frame_key = json!({
            "frame_seq": 91,
            "content_revision": 31,
            "layout_revision": 7,
            "render_scene_revision": 29,
            "surface_id": "preview:test-surface",
            "surface_epoch": 1,
            "input_event_seq": 14,
            "present_id": 91,
            "proof_request_id": null
        });
        let role_report = json!({
            "status": "pass",
            "details": {
                "app_window_surface_proof": {
                    "display_connection": "boon-test-socket",
                    "surface_id": "preview:test-surface",
                    "surface_epoch": 1,
                    "input_adapter": {
                        "installed": true,
                        "real_os_events_observed": true,
                        "synthetic_input_probe": false,
                        "mouse_scroll_event_count": 1,
                        "scroll_delta_y": 120.0,
                        "mouse_last_window_protocol_id": 7
                    },
                    "post_input_frame_timing": {
                        "measured_frame_count": 59,
                        "presented_frame_ms_p95": 10.0
                    },
                    "readback_artifact": {
                        "capture_method": "wgpu-visible-surface-copy-src-readback",
                        "readback_poll_status": "completed_before_deadline",
                        "nonblank_samples": 16,
                        "frame_evidence_key": {
                            "frame_seq": 2,
                            "content_revision": 1,
                            "layout_revision": 1,
                            "render_scene_revision": 1,
                            "surface_id": "preview:test-surface",
                            "surface_epoch": 1,
                            "input_event_seq": null,
                            "present_id": 2,
                            "proof_request_id": null
                        }
                    }
                }
            }
        });
        let loop_report = json!({
            "status": "pass",
            "surface_id": "preview:test-surface",
            "surface_epoch": 1,
            "frame_evidence_key": frame_key.clone(),
            "observed_input_adapter": {
                "installed": true,
                "real_os_events_observed": true,
                "synthetic_input_probe": false,
                "mouse_scroll_event_count": 3,
                "scroll_delta_y": 360.0,
                "mouse_last_window_protocol_id": 7
            },
            "last_external_render_proof": {
                "status": "pass",
                "render_backend_trait": "boon_native_gpu::encode_render_scene_to_surface",
                "offscreen_app_owned_scene_readback_skipped": true
            },
            "last_interactive_readback_artifact": {
                "capture_method": "wgpu-visible-surface-copy-src-readback",
                "readback_poll_status": "completed_before_deadline",
                "nonblank_samples": 32,
                "frame_evidence_key": frame_key
            }
        });

        let (adapter, adapter_source) = native_surface_input_adapter_from_reports(
            &json!({"status": "missing"}),
            &role_report,
            &loop_report,
            "preview_surface_proof",
        );
        assert_eq!(
            adapter_source,
            "measured-loop-report.observed_input_adapter"
        );
        assert_eq!(
            adapter
                .get("mouse_scroll_event_count")
                .and_then(serde_json::Value::as_u64),
            Some(3)
        );
        let (readback, readback_source) = native_surface_evidence_from_reports(
            &json!({"status": "missing"}),
            &role_report,
            &loop_report,
            "preview_surface_proof",
            "readback_artifact",
        );
        assert_eq!(
            readback_source,
            "measured-loop-report.last_interactive_readback_artifact"
        );
        assert_eq!(
            readback
                .get("nonblank_samples")
                .and_then(serde_json::Value::as_u64),
            Some(32)
        );
        let (timing, timing_source) = native_surface_evidence_from_reports(
            &json!({"status": "missing"}),
            &role_report,
            &loop_report,
            "preview_surface_proof",
            "post_input_frame_timing",
        );
        assert_eq!(
            timing_source,
            "measured-role-report.details.app_window_surface_proof.post_input_frame_timing"
        );
        assert_eq!(
            timing
                .get("measured_frame_count")
                .and_then(serde_json::Value::as_u64),
            Some(59)
        );
        assert!(same_frame_scroll_readback_proven(&loop_report));
        assert!(native_surface_role_loop_reports_match(
            "boon-test-socket",
            &role_report,
            &loop_report
        ));

        let mut stale_role = role_report;
        stale_role["details"]["app_window_surface_proof"]["display_connection"] =
            json!("different-socket");
        assert!(!native_surface_role_loop_reports_match(
            "boon-test-socket",
            &stale_role,
            &loop_report
        ));
    }

    #[test]
    fn native_scroll_axis_observation_requires_timing_and_same_frame_readback() {
        let mut observation = json!({
            "status": "pass",
            "wheel_input_observed": true,
            "real_os_events_observed": true,
            "measured_loop_same_frame_readback_proven": true,
            "post_input_timing_proven": true,
            "surface_input_adapter": {
                "mouse_scroll_event_count": 1,
                "scroll_delta_y": 120.0
            }
        });

        assert!(native_scroll_axis_observation_pass(
            &observation,
            "vertical"
        ));
        observation["post_input_timing_proven"] = json!(false);
        assert!(!native_scroll_axis_observation_pass(
            &observation,
            "vertical"
        ));
        observation["post_input_timing_proven"] = json!(true);
        observation["measured_loop_same_frame_readback_proven"] = json!(false);
        assert!(!native_scroll_axis_observation_pass(
            &observation,
            "vertical"
        ));
    }

    #[test]
    fn native_scroll_axis_score_prefers_best_failed_real_wheel_attempt() {
        let no_wheel_attempt = json!({
            "status": "fail",
            "wheel_input_observed": false,
            "real_os_events_observed": true,
            "measured_loop_same_frame_readback_proven": false,
            "post_input_timing_proven": true,
            "measured_role_loop_reports_match": true,
            "driver_pass": true,
            "desktop_pass": true,
            "surface_input_adapter": {
                "mouse_scroll_event_count": 0,
                "scroll_delta_x": 0.0,
                "scroll_delta_y": 0.0
            },
            "surface_post_input_frame_timing": {
                "presented_frame_ms_p95": 11.0
            }
        });
        let wheel_attempt_without_same_frame_proof = json!({
            "status": "fail",
            "wheel_input_observed": true,
            "real_os_events_observed": true,
            "measured_loop_same_frame_readback_proven": false,
            "post_input_timing_proven": true,
            "measured_role_loop_reports_match": true,
            "driver_pass": true,
            "desktop_pass": true,
            "surface_input_adapter": {
                "mouse_scroll_event_count": 1,
                "scroll_delta_x": 180.0,
                "scroll_delta_y": 0.0
            },
            "surface_post_input_frame_timing": {
                "presented_frame_ms_p95": 25.0
            }
        });
        let wheel_attempt_with_same_frame_proof = json!({
            "status": "pass",
            "wheel_input_observed": true,
            "real_os_events_observed": true,
            "measured_loop_same_frame_readback_proven": true,
            "post_input_timing_proven": true,
            "measured_role_loop_reports_match": true,
            "driver_pass": true,
            "desktop_pass": true,
            "surface_input_adapter": {
                "mouse_scroll_event_count": 1,
                "scroll_delta_x": 180.0,
                "scroll_delta_y": 0.0
            },
            "surface_post_input_frame_timing": {
                "presented_frame_ms_p95": 15.0
            }
        });

        assert!(
            native_scroll_axis_observation_score(
                &wheel_attempt_without_same_frame_proof,
                "horizontal"
            ) > native_scroll_axis_observation_score(&no_wheel_attempt, "horizontal")
        );
        assert!(
            native_scroll_axis_observation_score(
                &wheel_attempt_with_same_frame_proof,
                "horizontal"
            ) > native_scroll_axis_observation_score(
                &wheel_attempt_without_same_frame_proof,
                "horizontal"
            )
        );
    }

